                <div className="p-4 border-t border-gray-700 flex justify-end gap-3 bg-gray-800 z-10">
                    <button onClick={onClose} className="px-6 py-2 bg-gray-600 text-white rounded-md hover:bg-gray-500 transition btn-pressable">キャンセル</button>
                    <button onClick={handleSaveAction} className="px-8 py-2 bg-indigo-600 text-white rounded-md font-bold hover:bg-indigo-500 transition shadow-lg btn-pressable">保存</button>
                </div>
            </div>
        </div>,
        document.body
    );
};

