        });
    }, [localRelations]);

    const getSVGPoint = (e) => {
        const svg = svgRef.current;
        if (!svg) return { x: 0, y: 0 };
        const pt = svg.createSVGPoint();
        pt.x = e.clientX; pt.y = e.clientY;
        const screenCTM = svg.getScreenCTM();
        return screenCTM ? pt.matrixTransform(screenCTM.inverse()) : { x: 0, y: 0 };
    };

    if (!isOpen) return null;

    const nodesById = localNodes.reduce((acc, node) => ({ ...acc, [node.id]: node }), {});

    return createPortal(
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[70] p-4">
            {!isMobile && <ChartTutorial />}
            <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-5xl h-[90vh] flex flex-col border border-gray-700 relative overflow-hidden">
                <UnsavedChangesPopover isOpen={isConfirmCloseOpen} targetRef={closeButtonRef} onCancel={() => setIsConfirmCloseOpen(false)} onCloseWithoutSaving={onClose} onSaveAndClose={handleSaveAndClose} />

                <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0 bg-gray-800/50">
                    <h2 className="text-xl font-bold text-violet-400 flex items-center gap-2"><Icons.UserCogIcon />キャラクター相関図</h2>
                    <div className="flex items-center gap-2">
                        <div className="flex items-center p-1 bg-gray-900 rounded-lg shadow-inner">
                            {(['navigate', 'add_relation', 'delete_relation'] as const).map(m => (
                                <button key={m} onClick={() => { setMode(m); setFirstSelectionForAdd(null); }} className={`px-4 py-1.5 text-xs rounded transition-all ${mode === m ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-400 hover:text-white'} btn-pressable`}>
                                    {m === 'navigate' ? '移動' : m === 'add_relation' ? '追加' : '削除'}
                                </button>
                            ))}
                        </div>
                        <div className="w-px h-6 bg-gray-700 mx-2" />
                        <button onClick={() => onHelpClick('characterChart')} className="p-2 rounded-full text-gray-400 hover:text-white hover:bg-gray-700 transition btn-pressable"><Icons.HelpCircleIcon className="h-5 w-5"/></button>
                        <button ref={closeButtonRef} onClick={() => isDirty ? setIsConfirmCloseOpen(true) : onClose()} className="p-2 rounded-full hover:bg-gray-700 transition btn-pressable"><Icons.XIcon className="h-5 w-5 text-white" /></button>
                    </div>
                </div>

                <div className="flex-grow relative overflow-auto bg-gray-900/50" onClick={() => setFirstSelectionForAdd(null)}>
                    {mode === 'delete_relation' && (
                        <div className="absolute top-4 inset-x-0 mx-auto w-max z-30 bg-red-600 text-white px-4 py-1.5 rounded-full text-sm font-bold shadow-lg animate-bounce">
                            削除したい関係の線をクリックしてください
                        </div>
                    )}
                    {mode === 'add_relation' && (
                        <div className="absolute top-4 inset-x-0 mx-auto w-max z-30 bg-blue-600 text-white px-4 py-1.5 rounded-full text-sm font-bold shadow-lg">
                            {firstSelectionForAdd ? 'つなげたい相手のキャラを選択' : '関係の元となるキャラを選択'}
                        </div>
                    )}

                    <svg ref={svgRef} width="800" height="600" viewBox="0 0 800 600" className={`mx-auto ${mode === 'add_relation' ? 'cursor-crosshair' : ''}`}
                         onMouseMove={(e) => {
                             if (!activeDrag) return;
                             const p = getSVGPoint(e);
                             setLocalNodes(prev => prev.map(n => n.id === activeDrag.nodeId ? { ...n, x: p.x - activeDrag.offsetX, y: p.y - activeDrag.offsetY } : n));
                         }}
                         onMouseUp={() => setActiveDrag(null)}>

                        <g>
                            {relationsWithCurveData.map((rel, i) => {
                                const s = nodesById[rel.source], t = nodesById[rel.target];
                                if (!s || !t) return null;
                                const color = rel.color || "#6b7280";
                                const dx = t.x - s.x, dy = t.y - s.y, dist = Math.max(1, Math.sqrt(dx*dx + dy*dy));
                                const tx = t.x - (dx/dist)*35, ty = t.y - (dy/dist)*35;
                                const midX = (s.x + t.x)/2, midY = (s.y + t.y)/2;
                                const cx = midX - (dy/dist)*rel.curve, cy = midY + (dx/dist)*rel.curve;
                                const path = rel.curve ? `M ${s.x} ${s.y} Q ${cx} ${cy} ${tx} ${ty}` : `M ${s.x} ${s.y} L ${tx} ${ty}`;

                                const handleClick = (e) => {
                                    e.stopPropagation();
                                    if (mode === 'delete_relation') {
                                        handleDeleteLine(rel);
                                    } else if (mode === 'navigate') {
                                        setIsEditingRelation(rel);
                                    }
                                };

                                return (
                                    <g key={`${rel.id}-${i}`} className="cursor-pointer group" onClick={handleClick}>
                                        <path d={path} stroke="transparent" strokeWidth="25" fill="none" />
                                        <path d={path} stroke={color} strokeWidth={mode === 'delete_relation' ? "4" : "2"} fill="none" markerEnd={`url(#arrow-${rel.id})`} className="transition-all duration-200 group-hover:stroke-white" />
                                        <rect x={cx-25} y={cy-10} width="50" height="20" fill="#1f2937" rx="4" className="stroke-gray-600 border" />
                                        <text x={cx} y={cy} fill="white" fontSize="10" textAnchor="middle" dy=".3em" pointerEvents="none">{rel.label}</text>
                                        <defs>
                                            <marker id={`arrow-${rel.id}`} viewBox="0 0 10 10" refX="8" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
                                                <path d="M 0 0 L 10 5 L 0 10 z" fill={color} />
                                            </marker>
                                        </defs>
                                    </g>
                                );
                            })}
                        </g>

                        <g>
                            {localNodes.map(node => (
                                <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="cursor-pointer"
                                   onMouseDown={(e) => {
                                       if(mode!=='navigate') return;
                                       const p = getSVGPoint(e);
                                       setActiveDrag({ nodeId: node.id, offsetX: p.x - node.x, offsetY: p.y - node.y });
                                   }}
                                   onClick={(e) => handleNodeClick(e, node)}>
                                    <circle r="32" fill="#1a202c" stroke={firstSelectionForAdd === node.id ? "#3b82f6" : (node.themeColor || "#4b5563")} strokeWidth={firstSelectionForAdd === node.id ? "4" : "2"} className="transition-all" />
                                    <text fill="white" textAnchor="middle" dy=".3em" fontSize="11" pointerEvents="none" className="font-bold">{node.name}</text>
                                </g>
                            ))}
                        </g>
                    </svg>
                </div>

                {isEditingRelation && (
                    <RelationEditor 
                        relation={isEditingRelation} 
                        characters={characters} 
                        onClose={() => setIsEditingRelation(null)}
                        onDelete={(rel) => { handleDeleteLine(rel); setIsEditingRelation(null); }}
                        onSave={(saved) => {
                            // FIX: Added missing getRelId helper function to uniquely identify relations and fix the compilation error.
                            setLocalRelations(prev => prev.map(r => getRelId(r) === getRelId(saved) ? saved : r));
                            setIsEditingRelation(null);
                        }} 
                    />
                )}

                <div className="p-4 border-t border-gray-700 flex justify-end gap-3 bg-gray-800 z-10 shadow-[0_-4px_10px_rgba(0,0,0,0.3)]">
                    <button onClick={onClose} className="px-6 py-2 bg-gray-600 text-white rounded-md hover:bg-gray-500 transition btn-pressable">キャンセル</button>
                    <button onClick={handleSaveAction} className="px-8 py-2 bg-indigo-600 text-white rounded-md font-bold hover:bg-indigo-500 transition shadow-lg btn-pressable">保存</button>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { v4 as uuidv4 } from 'uuid';
import * as Icons from '../icons';
import { getContrastingTextColor } from '../utils';
import { SettingItem, Relation, NodePosition } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
import { useStore } from '../store/index';
import { ChartTutorial } from './ChartTutorial';

// 関係を一意に識別するヘルパー
const getRelId = (rel: Relation) => rel.id || `${rel.source}-${rel.target}-${rel.label}`;

export const RelationEditor = ({ relation, characters, onSave, onDelete, onClose }) => {
    const [label, setLabel] = useState(relation.label);
    const [color, setColor] = useState(relation.color);
    const [targetId, setTargetId] = useState(relation.target);
    const [callName, setCallName] = useState(relation.callName || '');

    const sourceChar = characters.find(c => c.id === relation.source);
    const targetChar = characters.find(c => c.id === targetId);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const handleSave = () => {
        onSave({ ...relation, label, color, target: targetId, callName });
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            handleSave();
        }
    };

    const presetColors = {
        '友好': '#14b8a6', '敵対': '#f43f5e', '協力': '#0ea5e9',
        '恋愛': '#d946ef', '家族': '#f59e0b', '師弟': '#8b5cf6', '不明': '#6b7280'
    };

    return (
        <div className="absolute bottom-0 left-0 right-0 bg-gray-900/90 backdrop-blur-sm border-t border-gray-700 p-4 z-20 shadow-2xl animate-in slide-in-from-bottom duration-200" onKeyDown={handleKeyDown}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">
                    <Icons.EditIcon className="h-5 w-5 text-indigo-400"/>
                    関係を編集
                </h3>
                <div className="flex items-center gap-2">
                    <button 
                        type="button" 
                        onClick={() => { if(window.confirm('この関係を削除しますか？')) onDelete(relation); }} 
                        className="flex items-center gap-1 px-3 py-1 bg-red-900/50 text-red-400 border border-red-800 rounded hover:bg-red-800 hover:text-white transition btn-pressable text-xs"
                    >
                        <Icons.TrashIcon className="h-3 w-3"/>
                        この関係を削除
                    </button>
                    <button type="button" onClick={onClose} className="p-1 rounded-full hover:bg-gray-700 btn-pressable"><Icons.XIcon className="h-5 w-5 text-white"/></button>
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-4">
                    <p className="text-sm bg-gray-800 p-2 rounded border border-gray-700">
                        <span className="font-semibold text-blue-400">{sourceChar?.name || '不明'}</span>
                        <span className="text-gray-500 mx-2">→</span>
                        <span className="font-semibold text-green-400">{targetChar?.name || '不明'}</span>
                    </p>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">関係の相手</label>
                        <select value={targetId} onChange={e => setTargetId(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1.5 text-sm text-white focus:border-indigo-500 outline-none">
                            {characters.map(char => <option key={char.id} value={char.id}>{char.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">関係性 (ラベル)</label>
                        <input type="text" value={label} onChange={e => setLabel(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1.5 text-sm text-white focus:border-indigo-500 outline-none"/>
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">呼び方</label>
                        <input type="text" value={callName} onChange={e => setCallName(e.target.value)} placeholder="例: 〇〇さん" className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1.5 text-sm text-white focus:border-indigo-500 outline-none"/>
                    </div>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">クイック設定</label>
                        <div className="flex gap-2 flex-wrap">
                            {Object.entries(presetColors).map(([pl, pc]) => (
                                <button key={pl} type="button" onClick={() => { setLabel(pl); setColor(pc); }} className="px-2 py-1 text-[10px] rounded-full btn-pressable border border-transparent hover:border-white/50" style={{ backgroundColor: pc, color: getContrastingTextColor(pc) }}>{pl}</button>
                            ))}
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">線の色</label>
                        <input type="color" value={color} onChange={e => setColor(e.target.value)} className="w-full h-8 p-1 bg-gray-800 border border-gray-600 rounded-md cursor-pointer"/>
                    </div>
                </div>
            </div>
            <div className="flex justify-end gap-3 pt-4 mt-4 border-t border-gray-700/50">
                <button type="button" onClick={handleSave} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition font-bold btn-pressable shadow-lg">
                    <Icons.CheckIcon className="h-4 w-4" />保存 ({modifierKeyText}+Enter)
                </button>
            </div>
        </div>
    );
};

export const CharacterChartModal = ({ isOpen, onClose, characters, relations, nodePositions, onSave, onHelpClick, isMobile = false }) => {
    const [localNodes, setLocalNodes] = useState<(SettingItem & NodePosition)[]>([]);
    const [localRelations, setLocalRelations] = useState<Relation[]>([]);
    const [activeDrag, setActiveDrag] = useState<{nodeId: string, offsetX: number, offsetY: number} | null>(null);
    const [isEditingRelation, setIsEditingRelation] = useState<Relation | null>(null);
    const [mode, setMode] = useState<'navigate' | 'add_relation' | 'delete_relation'>('navigate');
    const [firstSelectionForAdd, setFirstSelectionForAdd] = useState<string | null>(null);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');

    const svgRef = useRef<SVGSVGElement>(null);
    const closeButtonRef = useRef(null);
    const isInitializedRef = useRef(false);

    const startChartTutorial = useStore(state => state.startChartTutorial);
    const hasCompletedGlobalChartTutorial = useStore(state => state.hasCompletedGlobalChartTutorial);

    // 初期化を完全に一回きりに制限（relationsの変更で再発火させない）
    useEffect(() => {
        if (isOpen && !isInitializedRef.current) {
            const sanitizedRelations = (relations || []).map(r => ({
                ...r,
                id: r.id || uuidv4()
            }));

            setLocalRelations(sanitizedRelations);

            const chartWidth = 800;
            const chartHeight = 600;
            const updatedNodes = characters.map((char, index) => {
                const existingPos = nodePositions.find(p => p.characterId === char.id);
                if (existingPos) return { ...char, ...existingPos };
                const angle = (index / characters.length) * 2 * Math.PI;
                const radius = 200;
                return {
                    ...char,
                    characterId: char.id,
                    x: chartWidth / 2 + radius * Math.cos(angle),
                    y: chartHeight / 2 + radius * Math.sin(angle),
                };
            });
            setLocalNodes(updatedNodes);
            setInitialStateString(JSON.stringify({ relations: sanitizedRelations, nodePositions: updatedNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y })) }));

            isInitializedRef.current = true;

            if (!hasCompletedGlobalChartTutorial && !isMobile) {
                setTimeout(startChartTutorial, 300);
            }
        }

        return () => {
            if (!isOpen) {
                isInitializedRef.current = false;
            }
        };
    }, [isOpen]); 

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = {
            relations: localRelations,
            nodePositions: localNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y })),
        };
        return JSON.stringify(currentState) !== initialStateString;
    }, [localNodes, localRelations, initialStateString]);

    const handleSaveAction = () => {
        onSave(localRelations, localNodes.map(({ id, x, y }) => ({ characterId: id, x, y })));
        onClose();
    };

    const handleSaveAndClose = () => {
        handleSaveAction();
        setIsConfirmCloseOpen(false);
    };

    const handleDeleteLine = (rel: Relation) => {
        const idToDelete = getRelId(rel);
        setLocalRelations(prev => prev.filter(r => getRelId(r) !== idToDelete));
    };

    const handleNodeClick = (e, node) => {
        e.stopPropagation();
        if (mode === 'add_relation') {
            if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else if (firstSelectionForAdd !== node.id) {
                const newRel: Relation = { id: uuidv4(), source: firstSelectionForAdd, target: node.id, label: "関係", color: "#6b7280", callName: "" };
                setLocalRelations(prev => [...prev, newRel]);
                setIsEditingRelation(newRel);
                setFirstSelectionForAdd(null);
                setMode('navigate');
            }
        }
    };

    const relationsWithCurveData = useMemo(() => {
        const pairs = new Map<string, Relation[]>();
        localRelations.forEach(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            if (!pairs.has(key)) pairs.set(key, []);
            pairs.get(key)!.push(rel);
        });

        return localRelations.map(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            const pair = pairs.get(key)!;
            const isBidirectional = pair.length > 1 && pair.some(p => p.source === rel.target && p.target === rel.source);
            return { ...rel, curve: isBidirectional ? 30 : 0 };
        });
    }, [localRelations]);

    const getSVGPoint = (e) => {
        const svg = svgRef.current;
        if (!svg) return { x: 0, y: 0 };
        const pt = svg.createSVGPoint();
        pt.x = e.clientX; pt.y = e.clientY;
        const screenCTM = svg.getScreenCTM();
        return screenCTM ? pt.matrixTransform(screenCTM.inverse()) : { x: 0, y: 0 };
    };

    if (!isOpen) return null;

    const nodesById = localNodes.reduce((acc, node) => ({ ...acc, [node.id]: node }), {});

    return createPortal(
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[70] p-4">
            {!isMobile && <ChartTutorial />}
            <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-5xl h-[90vh] flex flex-col border border-gray-700 relative overflow-hidden">
                <UnsavedChangesPopover isOpen={isConfirmCloseOpen} targetRef={closeButtonRef} onCancel={() => setIsConfirmCloseOpen(false)} onCloseWithoutSaving={onClose} onSaveAndClose={handleSaveAndClose} />

                <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0 bg-gray-800/50">
                    <h2 className="text-xl font-bold text-violet-400 flex items-center gap-2"><Icons.UserCogIcon />キャラクター相関図</h2>
                    <div className="flex items-center gap-2">
                        <div className="flex items-center p-1 bg-gray-900 rounded-lg shadow-inner">
                            {(['navigate', 'add_relation', 'delete_relation'] as const).map(m => (
                                <button id={m === 'navigate' ? 'tutorial-chart-navigate-btn' : m === 'add_relation' ? 'tutorial-chart-add-btn' : 'tutorial-chart-delete-btn'} key={m} onClick={() => { setMode(m); setFirstSelectionForAdd(null); }} className={`px-4 py-1.5 text-xs rounded transition-all ${mode === m ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-400 hover:text-white'} btn-pressable`}>
                                    {m === 'navigate' ? '移動' : m === 'add_relation' ? '追加' : '削除'}
                                </button>
                            ))}
                        </div>
                        <div className="w-px h-6 bg-gray-700 mx-2" />
                        <button onClick={() => onHelpClick('characterChart')} className="p-2 rounded-full text-gray-400 hover:text-white hover:bg-gray-700 transition btn-pressable"><Icons.HelpCircleIcon className="h-5 w-5"/></button>
                        <button ref={closeButtonRef} onClick={() => isDirty ? setIsConfirmCloseOpen(true) : onClose()} className="p-2 rounded-full hover:bg-gray-700 transition btn-pressable"><Icons.XIcon className="h-5 w-5 text-white" /></button>
                    </div>
                </div>

                <div className="flex-grow relative overflow-auto bg-gray-900/50" onClick={() => setFirstSelectionForAdd(null)}>
                    {mode === 'delete_relation' && (
                        <div className="absolute top-4 inset-x-0 mx-auto w-max z-30 bg-red-600 text-white px-4 py-1.5 rounded-full text-sm font-bold shadow-lg animate-bounce">
                            削除したい関係の線をクリックしてください
                        </div>
                    )}
                    {mode === 'add_relation' && (
                        <div className="absolute top-4 inset-x-0 mx-auto w-max z-30 bg-blue-600 text-white px-4 py-1.5 rounded-full text-sm font-bold shadow-lg">
                            {firstSelectionForAdd ? 'つなげたい相手のキャラを選択' : '関係の元となるキャラを選択'}
                        </div>
                    )}

                    <svg id="tutorial-chart-svg" ref={svgRef} width="800" height="600" viewBox="0 0 800 600" className={`mx-auto ${mode === 'add_relation' ? 'cursor-crosshair' : ''}`}
                         onMouseMove={(e) => {
                             if (!activeDrag) return;
                             const p = getSVGPoint(e);
                             setLocalNodes(prev => prev.map(n => n.id === activeDrag.nodeId ? { ...n, x: p.x - activeDrag.offsetX, y: p.y - activeDrag.offsetY } : n));
                         }}
                         onMouseUp={() => setActiveDrag(null)}>

                        <g>
                            {relationsWithCurveData.map((rel, i) => {
                                const s = nodesById[rel.source], t = nodesById[rel.target];
                                if (!s || !t) return null;
                                const color = rel.color || "#6b7280";
                                const dx = t.x - s.x, dy = t.y - s.y, dist = Math.max(1, Math.sqrt(dx*dx + dy*dy));
                                const tx = t.x - (dx/dist)*35, ty = t.y - (dy/dist)*35;
                                const midX = (s.x + t.x)/2, midY = (s.y + t.y)/2;
                                const cx = midX - (dy/dist)*rel.curve, cy = midY + (dx/dist)*rel.curve;
                                const path = rel.curve ? `M ${s.x} ${s.y} Q ${cx} ${cy} ${tx} ${ty}` : `M ${s.x} ${s.y} L ${tx} ${ty}`;

                                const handleClick = (e) => {
                                    e.stopPropagation();
                                    if (mode === 'delete_relation') {
                                        handleDeleteLine(rel);
                                    } else if (mode === 'navigate') {
                                        setIsEditingRelation(rel);
                                    }
                                };

                                return (
                                    <g key={`${getRelId(rel)}-${i}`} className="cursor-pointer group" onClick={handleClick}>
                                        <path d={path} stroke="transparent" strokeWidth="25" fill="none" />
                                        <path d={path} stroke={color} strokeWidth={mode === 'delete_relation' ? "4" : "2"} fill="none" markerEnd={`url(#arrow-${rel.id})`} className="transition-all duration-200 group-hover:stroke-white" />
                                        <rect x={cx-25} y={cy-10} width="50" height="20" fill="#1f2937" rx="4" className="stroke-gray-600 border" />
                                        <text x={cx} y={cy} fill="white" fontSize="10" textAnchor="middle" dy=".3em" pointerEvents="none">{rel.label}</text>
                                        <defs>
                                            <marker id={`arrow-${rel.id}`} viewBox="0 0 10 10" refX="8" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
                                                <path d="M 0 0 L 10 5 L 0 10 z" fill={color} />
                                            </marker>
                                        </defs>
                                    </g>
                                );
                            })}
                        </g>

                        <g>
                            {localNodes.map(node => (
                                <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="cursor-pointer"
                                   onMouseDown={(e) => {
                                       if(mode!=='navigate') return;
                                       const p = getSVGPoint(e);
                                       setActiveDrag({ nodeId: node.id, offsetX: p.x - node.x, offsetY: p.y - node.y });
                                   }}
                                   onClick={(e) => handleNodeClick(e, node)}>
                                    <circle r="32" fill="#1a202c" stroke={firstSelectionForAdd === node.id ? "#3b82f6" : (node.themeColor || "#4b5563")} strokeWidth={firstSelectionForAdd === node.id ? "4" : "2"} className="transition-all" />
                                    <text fill="white" textAnchor="middle" dy=".3em" fontSize="11" pointerEvents="none" className="font-bold">{node.name}</text>
                                </g>
                            ))}
                        </g>
                    </svg>
                </div>

                {isEditingRelation && (
                    <RelationEditor 
                        relation={isEditingRelation} 
                        characters={characters} 
                        onClose={() => setIsEditingRelation(null)}
                        onDelete={(rel) => { handleDeleteLine(rel); setIsEditingRelation(null); }}
                        onSave={(saved) => {
                            setLocalRelations(prev => prev.map(r => getRelId(r) === getRelId(saved) ? saved : r));
                            setIsEditingRelation(null);
                        }} 
                    />
                )}

                <div className="p-4 border-t border-gray-700 flex justify-end gap-3 bg-gray-800 z-10 shadow-[0_-4px_10px_rgba(0,0,0,0.3)]">
                    <button onClick={onClose} className="px-6 py-2 bg-gray-600 text-white rounded-md hover:bg-gray-500 transition btn-pressable">キャンセル</button>
                    <button id="tutorial-chart-save-btn" onClick={handleSaveAction} className="px-8 py-2 bg-indigo-600 text-white rounded-md font-bold hover:bg-indigo-500 transition shadow-lg btn-pressable">保存</button>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { v4 as uuidv4 } from 'uuid';
import * as Icons from '../icons';
import { getContrastingTextColor } from '../utils';
import { SettingItem, Relation, NodePosition } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
import { useStore } from '../store/index';
import { ChartTutorial } from './ChartTutorial';

// 関係を一意に識別するヘルパー
const getRelId = (rel: Relation) => rel.id || `${rel.source}-${rel.target}-${rel.label}`;

export const RelationEditor = ({ relation, characters, onSave, onClose }) => {
    const [label, setLabel] = useState(relation.label);
    const [color, setColor] = useState(relation.color);
    const [targetId, setTargetId] = useState(relation.target);
    const [callName, setCallName] = useState(relation.callName || '');

    const sourceChar = characters.find(c => c.id === relation.source);
    const targetChar = characters.find(c => c.id === targetId);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const handleSave = () => {
        onSave({ ...relation, label, color, target: targetId, callName });
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            handleSave();
        }
    };

    const presetColors = {
        '友好': '#14b8a6', '敵対': '#f43f5e', '協力': '#0ea5e9',
        '恋愛': '#d946ef', '家族': '#f59e0b', '師弟': '#8b5cf6', '不明': '#6b7280'
    };

    return (
        <div className="absolute bottom-0 left-0 right-0 bg-gray-900/90 backdrop-blur-sm border-t border-gray-700 p-4 z-20 shadow-2xl animate-in slide-in-from-bottom duration-200" onKeyDown={handleKeyDown}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">
                    <Icons.EditIcon className="h-5 w-5 text-indigo-400"/>
                    関係を編集
                </h3>
                <div className="flex items-center gap-2">
                    {/* 削除ボタンを削除しました */}
                    <button type="button" onClick={onClose} className="p-1 rounded-full hover:bg-gray-700 btn-pressable"><Icons.XIcon className="h-5 w-5 text-white"/></button>
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-4">
                    <p className="text-sm bg-gray-800 p-2 rounded border border-gray-700">
                        <span className="font-semibold text-blue-400">{sourceChar?.name || '不明'}</span>
                        <span className="text-gray-500 mx-2">→</span>
                        <span className="font-semibold text-green-400">{targetChar?.name || '不明'}</span>
                    </p>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">関係の相手</label>
                        <select value={targetId} onChange={e => setTargetId(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1.5 text-sm text-white focus:border-indigo-500 outline-none">
                            {characters.map(char => <option key={char.id} value={char.id}>{char.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">関係性 (ラベル)</label>
                        <input type="text" value={label} onChange={e => setLabel(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1.5 text-sm text-white focus:border-indigo-500 outline-none"/>
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">呼び方</label>
                        <input type="text" value={callName} onChange={e => setCallName(e.target.value)} placeholder="例: 〇〇さん" className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1.5 text-sm text-white focus:border-indigo-500 outline-none"/>
                    </div>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">クイック設定</label>
                        <div className="flex gap-2 flex-wrap">
                            {Object.entries(presetColors).map(([pl, pc]) => (
                                <button key={pl} type="button" onClick={() => { setLabel(pl); setColor(pc); }} className="px-2 py-1 text-[10px] rounded-full btn-pressable border border-transparent hover:border-white/50" style={{ backgroundColor: pc, color: getContrastingTextColor(pc) }}>{pl}</button>
                            ))}
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs text-gray-400 mb-1">線の色</label>
                        <input type="color" value={color} onChange={e => setColor(e.target.value)} className="w-full h-8 p-1 bg-gray-800 border border-gray-600 rounded-md cursor-pointer"/>
                    </div>
                </div>
            </div>
            <div className="flex justify-end gap-3 pt-4 mt-4 border-t border-gray-700/50">
                <button type="button" onClick={handleSave} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition font-bold btn-pressable shadow-lg">
                    <Icons.CheckIcon className="h-4 w-4" />保存 ({modifierKeyText}+Enter)
                </button>
            </div>
        </div>
    );
};

export const CharacterChartModal = ({ isOpen, onClose, characters, relations, nodePositions, onSave, onHelpClick, isMobile = false }) => {
    const [localNodes, setLocalNodes] = useState<(SettingItem & NodePosition)[]>([]);
    const [localRelations, setLocalRelations] = useState<Relation[]>([]);
    const [activeDrag, setActiveDrag] = useState<{nodeId: string, offsetX: number, offsetY: number} | null>(null);
    const [isEditingRelation, setIsEditingRelation] = useState<Relation | null>(null);
    const [mode, setMode] = useState<'navigate' | 'add_relation' | 'delete_relation'>('navigate');
    const [firstSelectionForAdd, setFirstSelectionForAdd] = useState<string | null>(null);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');

    const svgRef = useRef<SVGSVGElement>(null);
    const closeButtonRef = useRef(null);
    const isInitializedRef = useRef(false);

    const startChartTutorial = useStore(state => state.startChartTutorial);
    const hasCompletedGlobalChartTutorial = useStore(state => state.hasCompletedGlobalChartTutorial);

    // 初期化を完全に一回きりに制限（relationsの変更で再発火させない）
    useEffect(() => {
        if (isOpen && !isInitializedRef.current) {
            const sanitizedRelations = (relations || []).map(r => ({
                ...r,
                id: r.id || uuidv4()
            }));

            setLocalRelations(sanitizedRelations);

            const chartWidth = 800;
            const chartHeight = 600;
            const updatedNodes = characters.map((char, index) => {
                const existingPos = nodePositions.find(p => p.characterId === char.id);
                if (existingPos) return { ...char, ...existingPos };
                const angle = (index / characters.length) * 2 * Math.PI;
                const radius = 200;
                return {
                    ...char,
                    characterId: char.id,
                    x: chartWidth / 2 + radius * Math.cos(angle),
                    y: chartHeight / 2 + radius * Math.sin(angle),
                };
            });
            setLocalNodes(updatedNodes);
            setInitialStateString(JSON.stringify({ relations: sanitizedRelations, nodePositions: updatedNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y })) }));

            isInitializedRef.current = true;

            if (!hasCompletedGlobalChartTutorial && !isMobile) {
                setTimeout(startChartTutorial, 300);
            }
        }

        return () => {
            if (!isOpen) {
                isInitializedRef.current = false;
            }
        };
    }, [isOpen]); 

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = {
            relations: localRelations,
            nodePositions: localNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y })),
        };
        return JSON.stringify(currentState) !== initialStateString;
    }, [localNodes, localRelations, initialStateString]);

    const handleSaveAction = () => {
        onSave(localRelations, localNodes.map(({ id, x, y }) => ({ characterId: id, x, y })));
        onClose();
    };

    const handleSaveAndClose = () => {
        handleSaveAction();
        setIsConfirmCloseOpen(false);
    };

    const handleDeleteLine = (rel: Relation) => {
        const idToDelete = getRelId(rel);
        setLocalRelations(prev => prev.filter(r => getRelId(r) !== idToDelete));
    };

    const handleNodeClick = (e, node) => {
        e.stopPropagation();
        if (mode === 'add_relation') {
            if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else if (firstSelectionForAdd !== node.id) {
                const newRel: Relation = { id: uuidv4(), source: firstSelectionForAdd, target: node.id, label: "関係", color: "#6b7280", callName: "" };
                setLocalRelations(prev => [...prev, newRel]);
                setIsEditingRelation(newRel);
                setFirstSelectionForAdd(null);
                setMode('navigate');
            }
        }
    };

    const relationsWithCurveData = useMemo(() => {
        const pairs = new Map<string, Relation[]>();
        localRelations.forEach(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            if (!pairs.has(key)) pairs.set(key, []);
            pairs.get(key)!.push(rel);
        });

        return localRelations.map(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            const pair = pairs.get(key)!;
            const isBidirectional = pair.length > 1 && pair.some(p => p.source === rel.target && p.target === rel.source);
            return { ...rel, curve: isBidirectional ? 30 : 0 };
        });
    }, [localRelations]);

    const getSVGPoint = (e) => {
        const svg = svgRef.current;
        if (!svg) return { x: 0, y: 0 };
        const pt = svg.createSVGPoint();
        pt.x = e.clientX; pt.y = e.clientY;
        const screenCTM = svg.getScreenCTM();
        return screenCTM ? pt.matrixTransform(screenCTM.inverse()) : { x: 0, y: 0 };
    };

    if (!isOpen) return null;

    const nodesById = localNodes.reduce((acc, node) => ({ ...acc, [node.id]: node }), {});

    return createPortal(
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[70] p-4">
            {!isMobile && <ChartTutorial />}
            <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-5xl h-[90vh] flex flex-col border border-gray-700 relative overflow-hidden">
                <UnsavedChangesPopover isOpen={isConfirmCloseOpen} targetRef={closeButtonRef} onCancel={() => setIsConfirmCloseOpen(false)} onCloseWithoutSaving={onClose} onSaveAndClose={handleSaveAndClose} />

                <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0 bg-gray-800/50">
                    <h2 className="text-xl font-bold text-violet-400 flex items-center gap-2"><Icons.UserCogIcon />キャラクター相関図</h2>
                    <div className="flex items-center gap-2">
                        <div className="flex items-center p-1 bg-gray-900 rounded-lg shadow-inner">
                            {(['navigate', 'add_relation', 'delete_relation'] as const).map(m => (
                                <button id={m === 'navigate' ? 'tutorial-chart-navigate-btn' : m === 'add_relation' ? 'tutorial-chart-add-btn' : 'tutorial-chart-delete-btn'} key={m} onClick={() => { setMode(m); setFirstSelectionForAdd(null); }} className={`px-4 py-1.5 text-xs rounded transition-all ${mode === m ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-400 hover:text-white'} btn-pressable`}>
                                    {m === 'navigate' ? '移動' : m === 'add_relation' ? '追加' : '削除'}
                                </button>
                            ))}
                        </div>
                        <div className="w-px h-6 bg-gray-700 mx-2" />
                        <button onClick={() => onHelpClick('characterChart')} className="p-2 rounded-full text-gray-400 hover:text-white hover:bg-gray-700 transition btn-pressable"><Icons.HelpCircleIcon className="h-5 w-5"/></button>
                        <button ref={closeButtonRef} onClick={() => isDirty ? setIsConfirmCloseOpen(true) : onClose()} className="p-2 rounded-full hover:bg-gray-700 transition btn-pressable"><Icons.XIcon className="h-5 w-5 text-white" /></button>
                    </div>
                </div>

                <div className="flex-grow relative overflow-auto bg-gray-900/50" onClick={() => setFirstSelectionForAdd(null)}>
                    {mode === 'delete_relation' && (
                        <div className="absolute top-4 inset-x-0 mx-auto w-max z-30 bg-red-600 text-white px-4 py-1.5 rounded-full text-sm font-bold shadow-lg animate-bounce">
                            削除したい関係の線をクリックしてください
                        </div>
                    )}
                    {mode === 'add_relation' && (
                        <div className="absolute top-4 inset-x-0 mx-auto w-max z-30 bg-blue-600 text-white px-4 py-1.5 rounded-full text-sm font-bold shadow-lg">
                            {firstSelectionForAdd ? 'つなげたい相手のキャラを選択' : '関係の元となるキャラを選択'}
                        </div>
                    )}

                    <svg id="tutorial-chart-svg" ref={svgRef} width="800" height="600" viewBox="0 0 800 600" className={`mx-auto ${mode === 'add_relation' ? 'cursor-crosshair' : ''}`}
                         onMouseMove={(e) => {
                             if (!activeDrag) return;
                             const p = getSVGPoint(e);
                             setLocalNodes(prev => prev.map(n => n.id === activeDrag.nodeId ? { ...n, x: p.x - activeDrag.offsetX, y: p.y - activeDrag.offsetY } : n));
                         }}
                         onMouseUp={() => setActiveDrag(null)}>

                        <g>
                            {relationsWithCurveData.map((rel, i) => {
                                const s = nodesById[rel.source], t = nodesById[rel.target];
                                if (!s || !t) return null;
                                const color = rel.color || "#6b7280";
                                const dx = t.x - s.x, dy = t.y - s.y, dist = Math.max(1, Math.sqrt(dx*dx + dy*dy));
                                const tx = t.x - (dx/dist)*35, ty = t.y - (dy/dist)*35;
                                const midX = (s.x + t.x)/2, midY = (s.y + t.y)/2;
                                const cx = midX - (dy/dist)*rel.curve, cy = midY + (dx/dist)*rel.curve;
                                const path = rel.curve ? `M ${s.x} ${s.y} Q ${cx} ${cy} ${tx} ${ty}` : `M ${s.x} ${s.y} L ${tx} ${ty}`;

                                const handleClick = (e) => {
                                    e.stopPropagation();
                                    if (mode === 'delete_relation') {
                                        handleDeleteLine(rel);
                                    } else if (mode === 'navigate') {
                                        setIsEditingRelation(rel);
                                    }
                                };

                                return (
                                    <g key={`${getRelId(rel)}-${i}`} className="cursor-pointer group" onClick={handleClick}>
                                        <path d={path} stroke="transparent" strokeWidth="25" fill="none" />
                                        <path d={path} stroke={color} strokeWidth={mode === 'delete_relation' ? "4" : "2"} fill="none" markerEnd={`url(#arrow-${rel.id})`} className="transition-all duration-200 group-hover:stroke-white" />
                                        <rect x={cx-25} y={cy-10} width="50" height="20" fill="#1f2937" rx="4" className="stroke-gray-600 border" />
                                        <text x={cx} y={cy} fill="white" fontSize="10" textAnchor="middle" dy=".3em" pointerEvents="none">{rel.label}</text>
                                        <defs>
                                            <marker id={`arrow-${rel.id}`} viewBox="0 0 10 10" refX="8" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
                                                <path d="M 0 0 L 10 5 L 0 10 z" fill={color} />
                                            </marker>
                                        </defs>
                                    </g>
                                );
                            })}
                        </g>

                        <g>
                            {localNodes.map(node => (
                                <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="cursor-pointer"
                                   onMouseDown={(e) => {
                                       if(mode!=='navigate') return;
                                       const p = getSVGPoint(e);
                                       setActiveDrag({ nodeId: node.id, offsetX: p.x - node.x, offsetY: p.y - node.y });
                                   }}
                                   onClick={(e) => handleNodeClick(e, node)}>
                                    <circle r="32" fill="#1a202c" stroke={firstSelectionForAdd === node.id ? "#3b82f6" : (node.themeColor || "#4b5563")} strokeWidth={firstSelectionForAdd === node.id ? "4" : "2"} className="transition-all" />
                                    <text fill="white" textAnchor="middle" dy=".3em" fontSize="11" pointerEvents="none" className="font-bold">{node.name}</text>
                                </g>
                            ))}
                        </g>
                    </svg>
                </div>

                {isEditingRelation && (
                    <RelationEditor 
                        relation={isEditingRelation} 
                        characters={characters} 
                        onClose={() => setIsEditingRelation(null)}
                        onSave={(saved) => {
                            setLocalRelations(prev => prev.map(r => getRelId(r) === getRelId(saved) ? saved : r));
                            setIsEditingRelation(null);
                        }} 
                    />
                )}

                <div className="p-4 border-t border-gray-700 flex justify-end gap-3 bg-gray-800 z-10 shadow-[0_-4px_10px_rgba(0,0,0,0.3)]">
                    <button onClick={onClose} className="px-6 py-2 bg-gray-600 text-white rounded-md hover:bg-gray-500 transition btn-pressable">キャンセル</button>
                    <button id="tutorial-chart-save-btn" onClick={handleSaveAction} className="px-8 py-2 bg-indigo-600 text-white rounded-md font-bold hover:bg-indigo-500 transition shadow-lg btn-pressable">保存</button>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import * as Icons from '../icons';

interface NameGeneratorProps {
    isOpen: boolean;
    onClose: () => void;
    onGenerate: (category: string, keywords: string) => Promise<string[]>;
    onApply: (name: string) => void;
    applyButtonText: string;
    initialCategory?: string;
    initialKeywords?: string;
    isContextual?: boolean;
}

export const NameGenerator: React.FC<NameGeneratorProps> = ({
    isOpen,
    onClose,
    onGenerate,
    onApply,
    applyButtonText,
    initialCategory = 'ファンタジー風',
    initialKeywords = '',
    isContextual = false
}) => {
    const [categories, setCategories] = useState<string[]>([]);
    const [categoryInput, setCategoryInput] = useState('');
    const [keywords, setKeywords] = useState(initialKeywords);
    const [generatedNames, setGeneratedNames] = useState<string[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const modalRef = useRef<HTMLDivElement>(null);
    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const presetCategories = ['ファンタジー風', 'SF風', '現代日本風', '中華風', '地名', '組織名', '技名'];

    useEffect(() => {
        if (isOpen) {
            setCategories(initialCategory ? [initialCategory] : []);
            setKeywords(initialKeywords);
            setGeneratedNames([]);
            setIsLoading(false);
            setCategoryInput('');
            // Focus the modal to capture key events
            setTimeout(() => modalRef.current?.focus(), 0);
        }
    }, [isOpen, initialCategory, initialKeywords]);

    const handleAddCategory = (cat: string) => {
        const newCat = cat.trim();
        if (newCat && !categories.includes(newCat)) {
            setCategories([...categories, newCat]);
        }
    };

    const handleRemoveCategory = (catToRemove: string) => {
        setCategories(categories.filter(cat => cat !== catToRemove));
    };

    const handleCategoryInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setCategoryInput(e.target.value);
    };

    const handleCategoryInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' || e.key === ',') {
            e.preventDefault();
            handleAddCategory(categoryInput);
            setCategoryInput('');
        }
    };

    const handleGenerateClick = async () => {
        if (isLoading) return;
        setIsLoading(true);
        setGeneratedNames([]);
        const categoryString = categories.join(', ');
        const names = await onGenerate(categoryString, keywords);
        setGeneratedNames(names);
        setIsLoading(false);
    };

    const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
        if (event.key === 'Escape') {
            onClose();
        } else if ((event.ctrlKey || event.metaKey) && event.key === 'Enter') {
            event.preventDefault();
            event.stopPropagation();
            handleGenerateClick();
        }
    };

    if (!isOpen) return null;

    const modalTitle = isContextual ? `${initialCategory}を生成` : '固有名詞ジェネレーター';

    return createPortal(
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-[80]">
            <div
                ref={modalRef}
                tabIndex={-1} // Make it focusable to receive key events
                className="bg-gray-800 rounded-lg shadow-xl w-full max-w-md border border-gray-700 max-h-[90vh] flex flex-col outline-none"
                onKeyDown={handleKeyDown}
            >
                <div className="flex justify-between items-center p-6 pb-4 border-b border-gray-700 flex-shrink-0">
                    <h2 className="text-xl font-bold text-teal-400 flex items-center gap-2">
                        {isContextual ? <Icons.SparklesIcon className="h-6 w-6" /> : <Icons.DiceIcon className="h-6 w-6" />}
                        {modalTitle}
                    </h2>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-700 transition text-white"><Icons.XIcon /></button>
                </div>

                <div className="flex-grow overflow-y-auto p-6 min-h-0">
                    <div className="space-y-4">
                        {!isContextual && (
                            <div>
                                <label className="block text-sm font-medium text-gray-300 mb-1">カテゴリ</label>
                                <div className="flex flex-wrap items-center gap-2 p-2 bg-gray-900 border border-gray-600 rounded-md">
                                    {categories.map((cat) => (
                                        <span key={cat} className="flex items-center gap-1 bg-indigo-600 text-white text-xs font-medium pl-2.5 pr-1.5 py-1 rounded-full">
                                            {cat}
                                            <button onClick={() => handleRemoveCategory(cat)} className="text-indigo-200 hover:text-white">
                                                <Icons.XIcon className="h-3 w-3" />
                                            </button>
                                        </span>
                                    ))}
                                    <input
                                        type="text"
                                        value={categoryInput}
                                        onChange={handleCategoryInputChange}
                                        onKeyDown={handleCategoryInputKeyDown}
                                        onBlur={() => { handleAddCategory(categoryInput); setCategoryInput(''); }}
                                        placeholder={categories.length > 0 ? 'さらに追加...' : 'カテゴリを入力または選択...'}
                                        className="bg-transparent focus:outline-none text-sm text-white flex-grow min-w-[120px]"
                                    />
                                </div>
                                <div className="flex flex-wrap gap-2 mt-2">
                                    {presetCategories.filter(pc => !categories.includes(pc)).map(cat => (
                                        <button type="button" key={cat} onClick={() => { handleAddCategory(cat); }} className="px-2 py-1 text-xs rounded-full bg-gray-700 hover:bg-gray-600 transition text-gray-300">
                                            + {cat}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">キーワード (任意)</label>
                            <input type="text" value={keywords} onChange={e => setKeywords(e.target.value)} placeholder="例: 炎, 伝説, 女性" className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white" />
                        </div>
                    </div>

                    <div className="mt-6">
                        <button onClick={handleGenerateClick} disabled={isLoading} className="w-full flex items-center justify-center gap-2 px-4 py-2 text-sm rounded-md disabled:bg-gray-500 btn-pressable btn-invert-indigo">
                            {isLoading ? <Icons.LoaderIcon className="h-5 w-5" /> : <Icons.MagicWandIcon />}
                            {isLoading ? '生成中...' : `名前を生成 (${modifierKeyText}+Enter)`}
                        </button>
                    </div>

                    <div className="mt-6">
                        <h3 className="text-lg font-semibold text-gray-300 mb-2 border-t border-gray-700 pt-4">生成結果</h3>
                        {isLoading ? (
                            <div className="flex justify-center items-center h-24">
                                <Icons.LoaderIcon className="h-8 w-8 text-indigo-400" />
                            </div>
                        ) : generatedNames.length > 0 ? (
                            <ul className="space-y-2">
                                {generatedNames.map((name, index) => (
                                    <li key={index} className="flex items-center justify-between bg-gray-900/50 p-2 rounded-md">
                                        <span className="text-white">{name}</span>
                                        <button onClick={() => onApply(name)} className="px-3 py-1 text-xs rounded-md btn-pressable btn-invert-teal">{applyButtonText}</button>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <p className="text-sm text-gray-500 text-center py-4">ここに名前が生成されます。</p>
                        )}
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import * as Icons from '../icons';

interface NameGeneratorProps {
    isOpen: boolean;
    onClose: () => void;
    onGenerate: (category: string, keywords: string) => Promise<string[]>;
    onApply: (name: string) => void;
    applyButtonText: string;
    initialCategory?: string;
    initialKeywords?: string;
    isContextual?: boolean;
}

export const NameGenerator: React.FC<NameGeneratorProps> = ({
    isOpen,
    onClose,
    onGenerate,
    onApply,
    applyButtonText,
    initialCategory = 'ファンタジー風',
    initialKeywords = '',
    isContextual = false
}) => {
    const [categories, setCategories] = useState<string[]>([]);
    const [categoryInput, setCategoryInput] = useState('');
    const [keywords, setKeywords] = useState(initialKeywords);
    const [generatedNames, setGeneratedNames] = useState<string[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const modalRef = useRef<HTMLDivElement>(null);
    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const presetCategories = ['ファンタジー風', 'SF風', '現代日本風', '中華風', '地名', '組織名', '技名'];

    useEffect(() => {
        if (isOpen) {
            setCategories(initialCategory ? [initialCategory] : []);
            setKeywords(initialKeywords);
            setGeneratedNames([]);
            setIsLoading(false);
            setCategoryInput('');
            // Focus the modal to capture key events
            setTimeout(() => modalRef.current?.focus(), 0);
        }
    }, [isOpen, initialCategory, initialKeywords]);

    const handleAddCategory = (cat: string) => {
        const newCat = cat.trim();
        if (newCat && !categories.includes(newCat)) {
            setCategories([...categories, newCat]);
        }
    };

    const handleRemoveCategory = (catToRemove: string) => {
        setCategories(categories.filter(cat => cat !== catToRemove));
    };

    const handleCategoryInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setCategoryInput(e.target.value);
    };

    const handleCategoryInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' || e.key === ',') {
            e.preventDefault();
            handleAddCategory(categoryInput);
            setCategoryInput('');
        }
    };

    const handleGenerateClick = async () => {
        if (isLoading) return;
        setIsLoading(true);
        setGeneratedNames([]);
        const categoryString = categories.join(', ');
        const names = await onGenerate(categoryString, keywords);
        setGeneratedNames(names);
        setIsLoading(false);
    };

    const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
        if (event.key === 'Escape') {
            onClose();
        } else if ((event.ctrlKey || event.metaKey) && event.key === 'Enter') {
            event.preventDefault();
            event.stopPropagation();
            handleGenerateClick();
        }
    };

    if (!isOpen) return null;

    const modalTitle = isContextual ? `${initialCategory}を生成` : '固有名詞ジェネレーター';

    return createPortal(
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-[80]">
            <div
                ref={modalRef}
                tabIndex={-1} // Make it focusable to receive key events
                className="bg-gray-800 rounded-lg shadow-xl w-full max-w-md border border-gray-700 max-h-[90vh] flex flex-col outline-none"
                onKeyDown={handleKeyDown}
            >
                <div className="flex justify-between items-center p-6 pb-4 border-b border-gray-700 flex-shrink-0">
                    <h2 className="text-xl font-bold text-teal-400 flex items-center gap-2">
                        {isContextual ? <Icons.SparklesIcon className="h-6 w-6" /> : <Icons.DiceIcon className="h-6 w-6" />}
                        {modalTitle}
                    </h2>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-700 transition text-white"><Icons.XIcon /></button>
                </div>

                <div className="flex-grow overflow-y-auto p-6 min-h-0">
                    <div className="space-y-4">
                        {!isContextual && (
                            <div>
                                <label className="block text-sm font-medium text-gray-300 mb-1">カテゴリ</label>
                                <div className="flex flex-wrap items-center gap-2 p-2 bg-gray-900 border border-gray-600 rounded-md">
                                    {categories.map((cat) => (
                                        <span key={cat} className="flex items-center gap-1 bg-indigo-600 text-white text-xs font-medium pl-2.5 pr-1.5 py-1 rounded-full">
                                            {cat}
                                            <button onClick={() => handleRemoveCategory(cat)} className="text-indigo-200 hover:text-white">
                                                <Icons.XIcon className="h-3 w-3" />
                                            </button>
                                        </span>
                                    ))}
                                    <input
                                        type="text"
                                        value={categoryInput}
                                        onChange={handleCategoryInputChange}
                                        onKeyDown={handleCategoryInputKeyDown}
                                        onBlur={() => { handleAddCategory(categoryInput); setCategoryInput(''); }}
                                        placeholder={categories.length > 0 ? 'さらに追加...' : 'カテゴリを入力または選択...'}
                                        className="bg-transparent focus:outline-none text-sm text-white flex-grow min-w-[120px]"
                                    />
                                </div>
                                <div className="flex flex-wrap gap-2 mt-2">
                                    {presetCategories.filter(pc => !categories.includes(pc)).map(cat => (
                                        <button type="button" key={cat} onClick={() => { handleAddCategory(cat); }} className="px-2 py-1 text-xs rounded-full bg-gray-700 hover:bg-gray-600 transition text-gray-300">
                                            + {cat}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">キーワード (任意)</label>
                            <input type="text" value={keywords} onChange={e => setKeywords(e.target.value)} placeholder="例: 炎, 伝説, 女性" className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white" />
                        </div>
                    </div>

                    <div className="mt-6">
                        <button onClick={handleGenerateClick} disabled={isLoading} className="w-full flex items-center justify-center gap-2 px-4 py-2 text-sm rounded-md disabled:bg-gray-500 btn-pressable btn-invert-indigo">
                            {isLoading ? <Icons.LoaderIcon className="h-5 w-5" /> : <Icons.MoonIcon className="h-5 w-5" />}
                            {isLoading ? '生成中...' : `名前を生成 (${modifierKeyText}+Enter)`}
                        </button>
                    </div>

                    <div className="mt-6">
                        <h3 className="text-lg font-semibold text-gray-300 mb-2 border-t border-gray-700 pt-4">生成結果</h3>
                        {isLoading ? (
                            <div className="flex justify-center items-center h-24">
                                <Icons.LoaderIcon className="h-8 w-8 text-indigo-400" />
                            </div>
                        ) : generatedNames.length > 0 ? (
                            <ul className="space-y-2">
                                {generatedNames.map((name, index) => (
                                    <li key={index} className="flex items-center justify-between bg-gray-900/50 p-2 rounded-md">
                                        <span className="text-white">{name}</span>
                                        <button onClick={() => onApply(name)} className="px-3 py-1 text-xs rounded-md btn-pressable btn-invert-teal">{applyButtonText}</button>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <p className="text-sm text-gray-500 text-center py-4">ここに名前が生成されます。</p>
                        )}
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import * as Icons from '../../icons';
import { SettingItem } from '../../types';
import { NameGenerator } from '../NameGenerator';
import * as utilityApi from '../../utilityApi';
import { UnsavedChangesPopover } from '../UnsavedChangesPopover';
import { HelpPopover } from '../HelpPopover';
import { useStore } from '../../store/index';
import { compressImage } from '../../utils';

interface CharacterFormProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (item: any) => void;
    itemToEdit: SettingItem | null;
    allSettings: SettingItem[];
    onOpenCharacterGenModal: (data: Partial<SettingItem> | null) => void;
    onOpenImageGenModal: () => void;
    onShowHelp: () => void;
    isMobile?: boolean;
}

export const CharacterForm: React.FC<CharacterFormProps> = ({
    isOpen,
    onClose,
    onSave,
    itemToEdit,
    allSettings,
    onOpenCharacterGenModal,
    onOpenImageGenModal,
    onShowHelp,
    isMobile = false,
}) => {
    // Local form state
    const [name, setName] = useState('');
    const [appearance, setAppearance] = useState<{ imageUrl: string; traits: { key: string; value: string }[] }>({ imageUrl: '', traits: [] });
    const [furigana, setFurigana] = useState('');
    const [gender, setGender] = useState('');
    const [age, setAge] = useState('');
    const [species, setSpecies] = useState('');
    const [firstPersonPronoun, setFirstPersonPronoun] = useState('');
    const [personality, setPersonality] = useState('');
    const [speechPattern, setSpeechPattern] = useState('');
    const [secret, setSecret] = useState('');
    const [themeColor, setThemeColor] = useState('');
    const [longDescription, setLongDescription] = useState('');
    const [memo, setMemo] = useState('');
    const [exportDescription, setExportDescription] = useState('');
    const [originSelection, setOriginSelection] = useState('');
    const [customOriginValue, setCustomOriginValue] = useState('');
    const [affiliationSelection, setAffiliationSelection] = useState('');
    const [customAffiliationValue, setCustomAffiliationValue] = useState('');

    const [activeTab, setActiveTab] = useState('profile');
    const [isNameGeneratorOpen, setIsNameGeneratorOpen] = useState(false);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    const originHelpRef = useRef(null);
    const [isOriginHelpOpen, setIsOriginHelpOpen] = useState(false);
    const affiliationHelpRef = useRef(null);
    const [isAffiliationHelpOpen, setIsAffiliationHelpOpen] = useState(false);

    // フィールドごとの変更済みフラグ
    const [editedFields, setEditedFields] = useState<Set<string>>(new Set());

    // Subscribe to external form data changes from AI modal
    const characterFormData = useStore(state => state.characterFormData);
    const resetFormData = useStore(state => state.resetFormData);

    const organizationOptions = useMemo(() => {
        if (!allSettings) return [];
        return allSettings.filter(item =>
            item.type === 'world' &&
            item.fields?.some(f => f.key === '種別' && ['国家', 'ギルド', '秘密結社', '企業'].includes(f.value))
        );
    }, [allSettings]);

    const locationOptions = useMemo(() => {
        if (!allSettings) return [];
        const organizationIds = new Set(organizationOptions.map(org => org.id));
        return allSettings.filter(item => item.type === 'world' && !organizationIds.has(item.id));
    }, [allSettings, organizationOptions]);

    // データの正規化を行う関数（比較とスナップショット用）
    const getNormalizedData = useCallback((data: any) => {
        return {
            name: data?.name || '',
            furigana: data?.furigana || '',
            gender: data?.gender || '',
            age: data?.age || '',
            species: data?.species || '',
            firstPersonPronoun: data?.firstPersonPronoun || '',
            personality: data?.personality || '',
            origin: data?.origin || '',
            affiliation: data?.affiliation || '',
            speechPattern: data?.speechPattern || '',
            secret: data?.secret || '',
            themeColor: data?.themeColor || '',
            longDescription: data?.longDescription || '',
            memo: data?.memo || '',
            exportDescription: data?.exportDescription || '',
            appearance: {
                imageUrl: data?.appearance?.imageUrl || '',
                traits: (data?.appearance?.traits || []).map((t: any) => ({
                    key: t.key || '',
                    value: t.value || ''
                }))
            }
        };
    }, []);

    const populateState = (data) => {
        if (!data) return;

        setName(data.name || '');
        setAppearance(data.appearance || { imageUrl: '', traits: [] });
        setFurigana(data.furigana || '');
        setGender(data.gender || '');
        setAge(data.age || '');
        setSpecies(data.species || '');
        setFirstPersonPronoun(data.firstPersonPronoun || '');
        setPersonality(data.personality || '');
        setSpeechPattern(data.speechPattern || '');
        setSecret(data.secret || '');
        setThemeColor(data.themeColor || '');
        setLongDescription(data.longDescription || '');
        setMemo(data.memo || '');
        setExportDescription(data.exportDescription || '');

        const initialOrigin = data.origin || '';
        const isStandardOrigin = locationOptions.some(o => o.name === initialOrigin);
        if (isStandardOrigin) {
            setOriginSelection(initialOrigin);
            setCustomOriginValue('');
        } else if (initialOrigin) {
            setOriginSelection('その他');
            setCustomOriginValue(initialOrigin);
        } else {
            setOriginSelection('');
            setCustomOriginValue('');
        }

        const initialAffiliation = data.affiliation || '';
        const isStandardAffiliation = organizationOptions.some(o => o.name === initialAffiliation);
        if (isStandardAffiliation) {
            setAffiliationSelection(initialAffiliation);
            setCustomAffiliationValue('');
        } else if (initialAffiliation) {
            setAffiliationSelection('その他');
            setCustomAffiliationValue(initialAffiliation);
        } else {
            setAffiliationSelection('');
            setCustomAffiliationValue('');
        }
    };

    useEffect(() => {
        if (Object.keys(characterFormData).length > 0) {
            const currentData = getCurrentState();
            const mergedData = { ...currentData, ...characterFormData };
            populateState(mergedData);
        }
    }, [characterFormData]);

    const getCurrentState = useCallback(() => {
        const finalOrigin = originSelection === 'その他' ? customOriginValue : originSelection;
        const finalAffiliation = affiliationSelection === 'その他' ? customAffiliationValue : affiliationSelection;
        return getNormalizedData({
            name, furigana, gender, age, species, firstPersonPronoun, personality, 
            origin: finalOrigin, affiliation: finalAffiliation, 
            speechPattern, secret, themeColor, longDescription, memo, exportDescription, 
            appearance
        });
    }, [name, furigana, gender, age, species, firstPersonPronoun, personality, originSelection, customOriginValue, affiliationSelection, customAffiliationValue, speechPattern, secret, themeColor, longDescription, memo, exportDescription, appearance, getNormalizedData]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        return JSON.stringify(getCurrentState()) !== initialStateString;
    }, [getCurrentState, initialStateString]);

    useEffect(() => {
        if (isOpen) {
            // itemToEditがnullまたは空オブジェクト（初期状態）の場合は新規作成とみなす
            const hasDataToEdit = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0);

            if (hasDataToEdit) {
                populateState(itemToEdit);
                useStore.getState().setFormData('character', itemToEdit);
                setInitialStateString(JSON.stringify(getNormalizedData(itemToEdit)));
            } else {
                resetFormData('character'); // ストアにある前回の残骸を消す
                const initialData = {
                    name: '',
                    appearance: { imageUrl: '', traits: [] },
                    furigana: '',
                    gender: '',
                    age: '',
                    species: '',
                    firstPersonPronoun: '',
                    personality: '',
                    origin: '',
                    affiliation: '',
                    speechPattern: '',
                    secret: '',
                    themeColor: '',
                    longDescription: '',
                    memo: '',
                    exportDescription: '',
                };
                populateState(initialData);
                setInitialStateString(JSON.stringify(getNormalizedData(initialData)));
            }

            setEditedFields(new Set());
            setActiveTab('profile');
        }
    }, [isOpen, itemToEdit, resetFormData, getNormalizedData]);

    useEffect(() => {
      if (!isMobile) return;
      const setVh = () => {
        document.documentElement.style.setProperty('--vh', `${window.innerHeight * 0.01}px`);
      };
      setVh();
      window.addEventListener('resize', setVh);
      return () => window.removeEventListener('resize', setVh);
    }, [isMobile]);

    const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const result = reader.result as string;
                const compressed = await compressImage(result);
                setAppearance(prev => ({ ...prev, imageUrl: compressed }));
                markEdited('imageUrl');
            };
            reader.readAsDataURL(file);
        }
    };

    const handleAddTrait = () => setAppearance(prev => ({ ...prev, traits: [...(prev?.traits || []), { key: '', value: '' }] }));
    const handleRemoveTrait = (index) => setAppearance(prev => ({ ...prev, traits: (prev?.traits || []).filter((_, i) => i !== index) }));
    const handleTraitChange = (index, prop, value) => { 
        const newTraits = [...(appearance?.traits || [])]; 
        newTraits[index][prop] = value; 
        setAppearance(prev => ({ ...prev, traits: newTraits })); 
        markEdited('traits');
    };

    const markEdited = (fieldName: string) => {
        setEditedFields(prev => new Set(prev).add(fieldName));
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!name.trim()) return;

        const characterData = {
            ...itemToEdit,
            ...getCurrentState(),
            type: 'character',
            appearance: { ...(appearance || {}), traits: (appearance?.traits || []).filter(t => t.key.trim() !== '') },
        };
        onSave(characterData);
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            (e.currentTarget as HTMLFormElement).requestSubmit();
        }
    };

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        (document.getElementById('character-form') as HTMLFormElement)?.requestSubmit();
        setIsConfirmCloseOpen(false);
    };

    const handleOpenCharacterGen = () => {
        const currentData = getCurrentState();
         const cleanedData: Partial<SettingItem> = Object.fromEntries(
            Object.entries(currentData).filter(([_, v]) => {
                if (typeof v === 'string') return v.trim() !== '';
                if (Array.isArray(v)) return v.length > 0;
                // FIX: Cast v to a specific object type to fix TypeScript error "Property 'imageUrl' does not exist on type 'object'".
                if (typeof v === 'object' && v !== null) { // for appearance
                    const app = v as { imageUrl?: string; traits?: any[] };
                    return (app.imageUrl && app.imageUrl.trim() !== '') || (app.traits && app.traits.length > 0);
                }
                return false;
            })
        );
        onOpenCharacterGenModal(Object.keys(cleanedData).length > 0 ? cleanedData : null);
    };

    const characterKeywords = useMemo(() => {
        const keywords = [
            species,
            personality,
            gender,
            ...(appearance?.traits || []).map(t => t.value)
        ];
        return keywords.filter(Boolean).join(', ');
    }, [species, personality, gender, appearance?.traits]);

    const handleGenerateNames = async (category: string, keywords: string): Promise<string[]> => {
        const result = await utilityApi.generateNames({ category, keywords });
        if (result.success === false) {
            alert(`名前の生成に失敗しました: ${result.error.message}`);
            return [];
        }
        return result.data;
    };

    const TabButton = ({ tabId, label }: { tabId: string; label: React.ReactNode }) => (
        <button type="button" onClick={() => setActiveTab(tabId)} className={`px-4 py-2 text-sm font-medium transition-colors ${activeTab === tabId ? 'border-b-2 border-indigo-400 text-indigo-400' : 'border-b-2 border-transparent text-gray-400 hover:text-gray-200'}`}>
            {label}
        </button>
    );

    const handleOriginSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setOriginSelection(e.target.value);
        if (e.target.value !== 'その他') setCustomOriginValue('');
        markEdited('origin');
    };

    const handleAffiliationSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setAffiliationSelection(e.target.value);
        if (e.target.value !== 'その他') setCustomAffiliationValue('');
        markEdited('affiliation');
    };

    const renderLabel = (label: string, fieldKey?: string, helpNode?: React.ReactNode) => {
        const isAuto = itemToEdit?.isAutoFilled && fieldKey && !editedFields.has(fieldKey);
        return (
            <div className="flex items-center justify-between mb-1">
                <div className="flex items-center gap-2">
                    <label className="text-sm font-medium text-gray-400">{label}</label>
                    {helpNode}
                    {isAuto && (
                        <span className="text-[10px] bg-indigo-500/20 text-indigo-400 border border-indigo-500/50 px-1.5 py-0.5 rounded font-bold animate-pulse">補完済み</span>
                    )}
                </div>
            </div>
        );
    };

    const modalTitle = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0) ? 'キャラクターを編集' : 'キャラクターを新規作成';
    const imageUrlValue = appearance?.imageUrl ?? '';

    // Styles for mobile optimization
    const modalContainerClass = isMobile 
    ? "bg-gray-900 w-full h-[100dvh] flex flex-col min-h-0 z-[60]" 
    : "bg-gray-800 rounded-lg shadow-xl w-full max-w-4xl border border-gray-700 max-h-[90vh] flex flex-col min-h-0 overflow-hidden";

    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    return (
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50"}>
            <div className={modalContainerClass}>
