interface WorldFormProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (item: any) => void;
    itemToEdit: SettingItem | null;
    allSettings: SettingItem[];
    onOpenWorldGenModal: (data: Partial<SettingItem> | null) => void;
    onShowHelp: () => void;
    isMobile?: boolean;
}

const fieldKeyToTemplateMap = new Map<string, { key: string, name: string }>();
Object.entries(worldTemplates).forEach(([templateKey, template]) => {
    template.fields.forEach(field => {
        fieldKeyToTemplateMap.set(field.key, { key: templateKey, name: template.name });
    });
});

const initialEmptyWorldState: Partial<SettingItem> = {
    name: '',
    fields: [],
    longDescription: '',
    memo: '',
    exportDescription: '',
    mapImageUrl: '',
};

export const WorldForm: React.FC<WorldFormProps> = ({
    isOpen,
    onClose,
    onSave,
    itemToEdit,
    onOpenWorldGenModal,
    onShowHelp,
    isMobile = false,
}) => {
    const [name, setName] = useState('');
    const [fields, setFields] = useState<Field[]>([]);
    const [longDescription, setLongDescription] = useState('');
    const [memo, setMemo] = useState('');
    const [exportDescription, setExportDescription] = useState('');
    const [mapImageUrl, setMapImageUrl] = useState('');

    const [activeTab, setActiveTab] = useState('profile');
    const [isMapViewerOpen, setIsMapViewerOpen] = useState(false);

    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({});

    const [isAiAssistantHelpOpen, setIsAiAssistantHelpOpen] = useState(false);
    const aiAssistantHelpRef = useRef(null);

    // 編集済みフラグ管理
    const [editedFields, setEditedFields] = useState<Set<string>>(new Set());

    const worldFormData = useStore(state => state.worldFormData);
    const resetFormData = useStore(state => state.resetFormData);

    // データの正規化を行う関数（比較とスナップショット用）
    const getNormalizedData = useCallback((data: any) => {
        return {
            name: data?.name || '',
            fields: (data?.fields || []).map((f: any) => ({
                key: f.key || '',
                value: f.value || ''
            })),
            longDescription: data?.longDescription || '',
            memo: data?.memo || '',
            exportDescription: data?.exportDescription || '',
            mapImageUrl: data?.mapImageUrl || '',
        };
    }, []);

    const populateState = (data) => {
        const safeData = data || initialEmptyWorldState;
        setName(safeData.name || '');
        setLongDescription(safeData.longDescription || '');
        setMemo(safeData.memo || '');
        setExportDescription(safeData.exportDescription || '');
        setMapImageUrl(safeData.mapImageUrl || '');

        if (safeData.fields) {
            const initialFields = (safeData.fields || []).map(f => {
                const templateInfo = fieldKeyToTemplateMap.get(f.key);
                return { 
                    ...f, 
                    id: uuidv4(),
                    groupKey: templateInfo?.key || 'custom',
                    groupName: templateInfo?.name || 'カスタム項目'
                };
            });
            setFields(initialFields);

            const initialExpanded = initialFields.reduce((acc, field) => {
                acc[field.groupKey] = true;
                return acc;
            }, {});
            setExpandedGroups(initialExpanded);
        } else {
            setFields([]);
            setExpandedGroups({});
        }
    };

    useEffect(() => {
        if (Object.keys(worldFormData).length > 0) {
            const currentData = getCurrentState();
            const mergedData = { ...currentData, ...worldFormData };
            populateState(mergedData);
        }
    }, [worldFormData]);

    const getCurrentState = useCallback(() => {
        return getNormalizedData({
            name,
            fields,
            longDescription,
            memo,
            exportDescription,
            mapImageUrl
        });
    }, [name, fields, longDescription, memo, exportDescription, mapImageUrl, getNormalizedData]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentStateString = JSON.stringify(getCurrentState());
        return currentStateString !== initialStateString;
    }, [getCurrentState, initialStateString]);

    useEffect(() => {
        if (isOpen) {
            // itemToEditがnullまたは空オブジェクト（初期状態）の場合は新規作成とみなす
            const hasDataToEdit = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0);

            if (hasDataToEdit) {
                populateState(itemToEdit);
                useStore.getState().setFormData('world', itemToEdit);
                setInitialStateString(JSON.stringify(getNormalizedData(itemToEdit)));
            } else {
                resetFormData('world'); // ストアにある前回の残骸を消す
                populateState(initialEmptyWorldState);
                setInitialStateString(JSON.stringify(getNormalizedData(initialEmptyWorldState)));
            }

            setEditedFields(new Set());
            setActiveTab('profile');
        }
    }, [isOpen, itemToEdit, resetFormData, getNormalizedData]);

    const handleAddField = (groupKey = 'custom', groupName = 'カスタム項目') => {
        const newField: Field = { id: uuidv4(), key: '', value: '', groupKey, groupName };
        setFields([...fields, newField]);
    };

    const handleRemoveField = (id: string) => setFields(fields.filter(f => f.id !== id));
    const handleFieldChange = (id: string, prop: 'key' | 'value', value: string) => {
        setFields(fields.map(f => f.id === id ? { ...f, [prop]: value } : f));
        markEdited('fields');
    };

    const markEdited = (fieldKey: string) => {
        setEditedFields(prev => new Set(prev).add(fieldKey));
    };

    const handleApplyTemplate = (templateKey: keyof typeof worldTemplates) => {
        const templateExists = fields.some(f => f.groupKey === templateKey);
        if (templateExists) return; 

        const template = worldTemplates[templateKey];
        const newFields: Field[] = template.fields.map(f => ({
            id: uuidv4(),
            key: f.key,
            value: f.value || '',
            groupKey: templateKey,
            groupName: template.name
        }));
        setFields(prev => [...newFields, ...prev]);
        setExpandedGroups(prev => ({ ...prev, [templateKey]: true }));
        markEdited('fields');
    };

    const handleRemoveGroup = (groupKey: string) => {
        setFields(prev => prev.filter(f => f.groupKey !== groupKey));
        setExpandedGroups(prev => {
            const newExpanded = { ...prev };
            delete newExpanded[groupKey];
            return newExpanded;
        });
        markEdited('fields');
    };

    const handleMapImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const result = reader.result as string;
                const compressed = await compressImage(result);
                setMapImageUrl(compressed);
                markEdited('mapImageUrl');
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!name.trim()) return;
        const stateToSave = getCurrentState();
        const finalFields = (stateToSave.fields || []).filter(f => f.key.trim() !== '');
        onSave({ ...itemToEdit, ...stateToSave, fields: finalFields, type: 'world' });
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            (e.currentTarget as HTMLFormElement).requestSubmit();
        }
    };

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        (document.getElementById('world-form') as HTMLFormElement)?.requestSubmit();
        setIsConfirmCloseOpen(false);
    };

    const handleOpenWorldGen = () => {
        const currentData = { name, fields: fields.filter(f => f.key.trim() || f.value.trim()) };
        const cleanedData: any = {};
        if (currentData.name.trim()) cleanedData.name = currentData.name.trim();
        const cleanedFields = currentData.fields.map(({id, groupKey, groupName, ...rest}) => rest).filter(f => f.key.trim() || f.value.trim());
        if(cleanedFields.length > 0) cleanedData.fields = cleanedFields;
        onOpenWorldGenModal(Object.keys(cleanedData).length > 0 ? cleanedData : null);
    };

    const TabButton = ({ tabId, label }: { tabId: string; label: React.ReactNode }) => (
        <button type="button" onClick={() => setActiveTab(tabId)} className={`px-4 py-2 text-sm font-medium transition-colors ${activeTab === tabId ? 'border-b-2 border-indigo-400 text-indigo-400' : 'border-b-2 border-transparent text-gray-400 hover:text-gray-200'}`}>
            {label}
        </button>
    );

    const renderLabel = (label: string, fieldKey?: string, helpNode?: React.ReactNode) => {
        const isAuto = itemToEdit?.isAutoFilled && fieldKey && !editedFields.has(fieldKey);
        return (
            <div className="flex items-center gap-2 mb-1">
                <label className="text-sm font-medium text-gray-400">{label}</label>
                {helpNode}
                {isAuto && (
                    <span className="text-[10px] bg-indigo-500/20 text-indigo-400 border border-indigo-500/50 px-1.5 py-0.5 rounded font-bold animate-pulse">補完済み</span>
                )}
            </div>
        );
    };

    const modalTitle = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0) ? '世界観を編集' : '世界観を新規作成';

    // Styles for mobile optimization
    const modalContainerClass = isMobile 
        ? "fixed inset-0 bg-gray-900 w-full h-[100dvh] flex flex-col z-[60]" 
        : "bg-gray-800 rounded-lg shadow-xl w-full max-w-4xl p-6 border border-gray-700 max-h-[90vh] flex flex-col";

    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    const renderFieldInput = (field: Field) => {
        const allTemplateFields = Object.values(worldTemplates).flatMap(t => t.fields);
        const templateField = allTemplateFields.find(f => f.key === field.key);

        if (templateField && templateField.type === 'select') {
            const isCustom = !templateField.options.includes(field.value);
            return (
                 <div className={`flex gap-2 ${isMobile ? 'flex-col' : 'items-center'}`}>
                    <select 
                        value={isCustom ? 'その他' : field.value}
                        onChange={e => handleFieldChange(field.id, 'value', e.target.value)}
                        className={`${isMobile ? 'w-full' : 'w-1/2'} ${inputClass}`}
                    >
                        {templateField.options.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                    </select>
                    {(isCustom || field.value === 'その他') && (
                        <input
                            type="text"
                            value={isCustom ? field.value : ''}
                            onChange={e => handleFieldChange(field.id, 'value', e.target.value)}
                            placeholder="内容を自由入力"
                            className={`${isMobile ? 'w-full' : 'w-1/2'} ${inputClass}`}
                            autoFocus
                        />
                    )}
                 </div>
            );
        }
        if (templateField && templateField.type === 'textarea') {
            return <textarea value={field.value} onChange={e => handleFieldChange(field.id, 'value', e.target.value)} placeholder={templateField.placeholder} rows={3} className={`${inputClass} resize-y`}/>
        }
        return <input type="text" value={field.value} onChange={e => handleFieldChange(field.id, 'value', e.target.value)} placeholder={templateField?.placeholder || '内容（例：ギル）'} className={inputClass}/>;
    };

    const groupedFields = useMemo(() => {
        return fields.reduce((acc, field) => {
            const key = field.groupKey || 'custom';
            if (!acc[key]) {
                acc[key] = { name: field.groupName || 'カスタム項目', items: [] };
            }
            acc[key].items.push(field);
            return acc;
        }, {} as Record<string, { name: string; items: Field[] }>);
    }, [fields]);

    const groupOrder = ['place', 'organization', 'magic_tech', 'event', 'item'];
    const isAiAssistantDisabled = fields.length === 0;

    return (
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50"}>
             <div className={modalContainerClass}>
                <UnsavedChangesPopover isOpen={isConfirmCloseOpen} targetRef={closeButtonRef} onCancel={() => setIsConfirmCloseOpen(false)} onCloseWithoutSaving={onClose} onSaveAndClose={handleSaveAndClose} />

                <div className={`flex justify-between items-center flex-shrink-0 ${isMobile ? 'p-4 border-b border-gray-700' : 'mb-4'}`}>
                    <h2 className={`font-bold text-indigo-400 flex items-center gap-2 ${isMobile ? 'text-lg' : 'text-xl'}`}><Icons.GlobeIcon />{modalTitle}</h2>
                    <div className="flex items-center gap-2">
                        <button type="button" onClick={onShowHelp} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.HelpCircleIcon className="h-5 w-5 text-white" /></button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-2 rounded-full hover:bg-gray-700 transition text-white"><Icons.XIcon /></button>
                    </div>
                </div>

                <div className={`flex border-b border-gray-700 mb-6 flex-shrink-0 ${isMobile ? 'overflow-x-auto' : ''}`}>
                    <TabButton tabId="profile" label="基本設定" />
                    <TabButton tabId="visual" label="ビジュアル" />
                    <TabButton tabId="ai_settings" label="AI設定" />
                </div>

                <form id="world-form" onSubmit={handleSubmit} onKeyDown={handleKeyDown} className={`flex-grow overflow-y-auto min-h-0 ${isMobile ? 'px-4 pb-24' : 'pr-2'}`}>
                    <div className="space-y-6">
                         {activeTab === 'profile' && (
                             <div className="space-y-6">
                                <div>
                                    {renderLabel("名前 *", "name")}
                                    <input type="text" value={name} onChange={e => { setName(e.target.value); markEdited('name'); }} className={inputClass} required />
                                </div>
                                <div>
                                    <label className="text-sm font-medium text-gray-400 mb-2 block">テンプレートから項目を選択</label>
                                    <div className="flex gap-2 flex-wrap">
                                        {Object.entries(worldTemplates).map(([key, template]) => (
                                            <button 
                                                key={key}
                                                type="button" 
                                                onClick={() => handleApplyTemplate(key as keyof typeof worldTemplates)} 
                                                className={`text-sm bg-gray-700 text-white rounded-md hover:bg-gray-600 transition disabled:opacity-50 ${isMobile ? 'py-2 px-4' : 'px-3 py-1'}`}
                                                disabled={!!groupedFields[key]}
                                            >
                                                {template.name}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    {groupOrder.map(key => {
                                        const group = groupedFields[key];
                                        if (!group) return null;
                                        const isExpanded = expandedGroups[key];
                                        return (
                                            <div key={key} className="bg-gray-900/50 rounded-lg">
                                                <div className="flex justify-between items-center p-2 cursor-pointer" onClick={() => setExpandedGroups(p => ({ ...p, [key]: !p[key] }))}>
                                                    <div className="flex items-center gap-2 min-w-0">
                                                        <div className="flex items-center gap-2 flex-shrink-0">
                                                            <h3 className="text-md font-semibold text-gray-300 whitespace-nowrap">{group.name}</h3>
                                                        </div>
                                                        {!isExpanded && (
                                                            <div className="text-xs text-gray-400 truncate">
                                                                {group.items.map(f => f.key).join(' / ')}
                                                            </div>
                                                        )}
                                                    </div>
                                                    <button type="button" onClick={(e) => { e.stopPropagation(); handleRemoveGroup(key); }} className="p-1 text-gray-500 hover:text-red-400 flex-shrink-0 ml-2"><Icons.TrashIcon /></button>
                                                </div>
                                                {isExpanded && (
                                                    <div className="p-4 pt-2 border-t border-gray-700/50 space-y-3">
                                                        {group.items.map((field) => (
                                                            <div key={field.id}>
                                                                <label className="text-sm font-medium text-gray-400 mb-1 block">{field.key}</label>
                                                                {renderFieldInput(field)}
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>

                                <div className="space-y-3 pt-4 border-t border-gray-700/50">
                                    <h3 className="text-lg font-semibold text-gray-300">カスタム項目</h3>
                                    {(groupedFields['custom']?.items || []).map((field) => (
                                        <div key={field.id} className="flex flex-col gap-2 pb-4 border-b border-gray-700/30 last:border-0">
                                            <div className="flex items-center gap-2">
                                                <input type="text" value={field.key} onChange={e => handleFieldChange(field.id, 'key', e.target.value)} placeholder="項目名（例：通貨）" className={`flex-1 ${inputClass}`}/>
                                                <button type="button" onClick={() => handleRemoveField(field.id)} className={`text-gray-500 hover:text-red-400 transition flex-shrink-0 ${isMobile ? 'p-3' : 'p-2'}`}><Icons.TrashIcon/></button>
                                            </div>
                                            {renderFieldInput(field)}
                                        </div>
                                    ))}
                                    <button type="button" onClick={() => handleAddField()} className={`w-full text-indigo-400 border-2 border-dashed border-gray-600 rounded-md hover:bg-gray-700/50 ${isMobile ? 'py-3 text-base' : 'py-1 text-sm'}`}>項目を追加</button>
                                </div>
                            </div>
                         )}

                         {activeTab === 'visual' && (
                             <div className="space-y-6">
                                <h3 className="text-lg font-semibold text-gray-300">地図・イメージ画像</h3>
                                <div>
                                    {renderLabel("画像URL", "mapImageUrl")}
                                    <input type="text" value={(mapImageUrl || '').startsWith('data:') ? '' : (mapImageUrl || '')} onChange={e => { setMapImageUrl(e.target.value); markEdited('mapImageUrl'); }} placeholder="https://..." className={inputClass}/>
                                </div>

                                <label className={`w-full flex items-center justify-center gap-2 text-indigo-300 border-2 border-dashed border-gray-600 rounded-lg hover:bg-gray-700/50 hover:border-indigo-500 cursor-pointer transition btn-pressable ${isMobile ? 'py-4 text-base' : 'py-2 text-sm'}`}>
                                    <input type="file" onChange={handleMapImageUpload} accept="image/*" className="hidden" />
                                    <Icons.UploadCloudIcon className="h-5 w-5" />
                                    <span>またはファイルを選択</span>
                                </label>
                                <div className="w-full aspect-video rounded-md bg-gray-900/50 flex items-center justify-center overflow-hidden relative">
                                    {mapImageUrl ? (
                                        <>
                                            <img src={mapImageUrl} alt="Map preview" className="object-contain w-full h-full" />
                                            <div className="absolute top-2 right-2 flex flex-col space-y-2">
                                                <button type="button" onClick={(e) => { e.stopPropagation(); setIsMapViewerOpen(true); }} className="p-2 bg-black/50 rounded-md text-white hover:bg-black/75 transition" title="拡大表示"><Icons.ExpandIcon className="h-5 w-5" /></button>
                                                <button type="button" onClick={(e) => { e.stopPropagation(); setMapImageUrl(''); markEdited('mapImageUrl'); }} className="p-2 bg-black/50 rounded-md text-white hover:bg-red-500/75 transition" title="画像を削除"><Icons.TrashIcon className="h-5 w-5" /></button>
                                            </div>
                                        </>
                                    ) : (
                                        <p className="text-gray-500">画像がありません</p>
                                    )}
                                </div>
                            </div>
                         )}

                         {activeTab === 'ai_settings' && (
                             <div className="space-y-6">
                                <div>
                                    {renderLabel("詳細設定 (AIが参照)", "longDescription", <Icons.BotIcon className="h-4 w-4 text-indigo-400" />)}
                                    <p className="text-xs text-gray-400 mb-2">物語の歴史、文化、地理、物理法則など、AIに記憶させておきたい情報を入力してください。</p>
                                    <textarea value={longDescription} onChange={e => { setLongDescription(e.target.value); markEdited('longDescription'); }} rows={8} className={`${inputClass} resize-y`}/>
                                </div>
                                <div>
                                    {renderLabel("メモ (AIは非参照)", "memo", <Icons.PenSquareIcon className="h-4 w-4 text-lime-400" />)}
                                    <p className="text-xs text-gray-400 mb-2">あなた専用のメモ欄です。</p>
                                    <textarea value={memo} onChange={e => { setMemo(e.target.value); markEdited('memo'); }} rows={5} className={`${inputClass} resize-y`}/>
                                </div>
                                <div>
                                    {renderLabel("書き出し用説明文", "exportDescription", <Icons.BookIcon className="h-4 w-4 text-orange-400" />)}
                                    <p className="text-xs text-gray-400 mb-2">HTML書き出し時に表示される説明文です。</p>
                                    <textarea value={exportDescription} onChange={e => { setExportDescription(e.target.value); markEdited('exportDescription'); }} rows={5} className={`${inputClass} resize-y`}/>
                                </div>
                            </div>
                         )}
                    </div>
                </form>

                <div className={`mt-auto border-t border-gray-700 pt-4 bg-gray-900/50 ${isMobile ? 'flex flex-col gap-3 px-4' : 'flex justify-between items-center mt-6'}`} style={isMobile ? { paddingBottom: 'calc(1rem + env(safe-area-inset-bottom))' } : {}}>
                    <div ref={aiAssistantHelpRef} onMouseEnter={() => isAiAssistantDisabled && setIsAiAssistantHelpOpen(true)} onMouseLeave={() => setIsAiAssistantHelpOpen(false)} className={isMobile ? 'w-full order-1' : ''}>
                        <button type="button" onClick={handleOpenWorldGen} disabled={isAiAssistantDisabled} className={`flex items-center justify-center gap-2 font-semibold btn-pressable bg-teal-600 text-white hover:bg-teal-500 disabled:bg-gray-600 disabled:cursor-not-allowed ${isMobile ? 'w-full py-3 rounded-md text-base' : 'px-4 py-2 text-sm rounded-md transition'}`}><Icons.MoonIcon className={isMobile ? "h-5 w-5" : "h-4 w-4"} /><span>AIアシスタント</span></button>
                    </div>
                    <div className={`flex gap-3 ${isMobile ? 'flex-col w-full order-2' : ''}`}>
                        <button type="button" onClick={handleCloseRequest} className={buttonClass('bg-gray-600 hover:bg-gray-500')}><Icons.XIcon className="h-4 w-4" />キャンセル</button>
                        <button type="submit" form="world-form" data-testid="modal-save-button" className={buttonClass('bg-indigo-600 hover:bg-indigo-500 font-bold')}><Icons.CheckIcon className="h-4 w-4" />保存</button>
                    </div>
                </div>
            </div>
            {isMapViewerOpen && <MapViewerModal imageUrl={mapImageUrl} onClose={() => setIsMapViewerOpen(false)} />}
        </div>
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import * as Icons from '../icons';
import { KnowledgeItem } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
import { HelpPopover } from './HelpPopover';
import { useStore } from '../store/index';

export const KnowledgeModal: React.FC<{
    isOpen: boolean;
    onClose: () => void;
    onSave: (item: Partial<KnowledgeItem>, type?: 'knowledge') => void;
    itemToEdit: KnowledgeItem | null;
    allKnowledge: KnowledgeItem[];
    isMobile?: boolean;
}> = ({
    isOpen,
    onClose,
    onSave,
    itemToEdit,
    allKnowledge,
    isMobile = false,
}) => {
    const [name, setName] = useState('');
    const [content, setContent] = useState('');
    const [category, setCategory] = useState('');
    const [tags, setTags] = useState<string[]>([]);
    const [tagInput, setTagInput] = useState('');
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef<HTMLButtonElement>(null);
    const [isCategoryHelpOpen, setIsCategoryHelpOpen] = useState(false);
    const categoryHelpRef = useRef<HTMLButtonElement>(null);
    const setHelpTopic = useStore((state: any) => state.setHelpTopic);

    // 編集済みフラグ管理
    const [editedFields, setEditedFields] = useState<Set<string>>(new Set());

    useEffect(() => {
        if (isOpen) {
            const initialData = {
                name: itemToEdit?.name || '',
                content: itemToEdit?.content || '',
                category: itemToEdit?.category || '未分類',
                tags: itemToEdit?.tags || [],
            };
            setName(initialData.name);
            setContent(initialData.content);
            setCategory(initialData.category);
            setTags(initialData.tags);
            setTagInput('');
            setEditedFields(new Set());
            setInitialStateString(JSON.stringify(initialData));
        }
    }, [isOpen, itemToEdit]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = { name, content, category, tags };
        return JSON.stringify(currentState) !== initialStateString;
    }, [name, content, category, tags, initialStateString]);

    const existingCategories = useMemo(() => {
        if (!allKnowledge) return ['未分類'];
        const categories = new Set(allKnowledge.map(k => k.category).filter(Boolean));
        return ['未分類', ...Array.from(categories)];
    }, [allKnowledge]);

    const handleTagInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' || e.key === ',') {
            e.preventDefault();
            const newTag = tagInput.trim();
            if (newTag && !tags.includes(newTag)) {
                setTags([...tags, newTag]);
                markEdited('tags');
            }
            setTagInput('');
        }
    };

    const handleRemoveTag = (tagToRemove: string) => {
        setTags(tags.filter(tag => tag !== tagToRemove));
        markEdited('tags');
    };

    const markEdited = (fieldKey: string) => {
        setEditedFields(prev => new Set(prev).add(fieldKey));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;
        onSave({ ...itemToEdit, name, content, category, tags }, 'knowledge');
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            e.currentTarget.requestSubmit();
        }
    };

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        (document.getElementById('knowledge-form') as HTMLFormElement)?.requestSubmit();
        setIsConfirmCloseOpen(false);
    };

    const renderLabel = (label: string, fieldKey?: string, helpNode?: React.ReactNode) => {
        const isAuto = itemToEdit?.isAutoFilled && fieldKey && !editedFields.has(fieldKey);
        return (
            <div className="flex items-center gap-2 mb-1">
                <label className="text-sm font-medium text-gray-300">{label}</label>
                {helpNode}
                {isAuto && (
                    <span className="text-[10px] bg-indigo-500/20 text-indigo-400 border border-indigo-500/50 px-1.5 py-0.5 rounded font-bold animate-pulse">補完済み</span>
                )}
            </div>
        );
    };

    if (!isOpen) return null;

    const modalContainerClass = isMobile 
        ? "fixed inset-0 bg-gray-900 w-full h-[100dvh] flex flex-col z-[60]"
        : "bg-gray-800 rounded-lg shadow-xl w-full max-w-2xl p-6 border border-gray-700 max-h-[90vh] flex flex-col";

    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    return createPortal(
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-[80]"}>
            <div className={modalContainerClass}>
                <UnsavedChangesPopover
                    isOpen={isConfirmCloseOpen}
                    targetRef={closeButtonRef}
                    onCancel={() => setIsConfirmCloseOpen(false)}
                    onCloseWithoutSaving={() => { setIsConfirmCloseOpen(false); onClose(); }}
                    onSaveAndClose={handleSaveAndClose}
                />

                <div className={`flex justify-between items-center flex-shrink-0 ${isMobile ? 'p-4 border-b border-gray-700' : 'mb-4'}`}>
                    <h2 className={`font-bold text-yellow-400 flex items-center gap-2 ${isMobile ? 'text-lg' : 'text-xl'}`}>
                        <Icons.LightbulbIcon />
                        {itemToEdit ? 'ナレッジを編集' : 'ナレッジを新規作成'}
                    </h2>
                    <div className="flex items-center gap-2">
                        <button type="button" onClick={() => setHelpTopic && setHelpTopic('knowledgeBase')} className="p-2 rounded-full hover:bg-gray-700 transition" aria-label="ヘルプ">
                            <Icons.HelpCircleIcon className="h-5 w-5 text-white" />
                        </button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-2 rounded-full hover:bg-gray-700 transition text-white"><Icons.XIcon /></button>
                    </div>
                </div>

                <form id="knowledge-form" onSubmit={handleSubmit} onKeyDown={handleKeyDown} className={`flex-grow overflow-y-auto min-h-0 ${isMobile ? 'px-4 pb-24' : 'pr-2'}`}>
                    <div className="space-y-6">
                        <div>
                            {renderLabel("名前 *", "name")}
                            <input
                                id="knowledge-name"
                                type="text"
                                value={name}
                                onChange={e => { setName(e.target.value); markEdited('name'); }}
                                className={inputClass}
                                required
                            />
                        </div>
                        <div className={`grid ${isMobile ? 'grid-cols-1 gap-6' : 'grid-cols-1 md:grid-cols-2 gap-4'}`}>
                            <div>
                                {renderLabel("カテゴリ", "category", (
                                    <button type="button" ref={categoryHelpRef} onMouseEnter={() => setIsCategoryHelpOpen(true)} onMouseLeave={() => setIsCategoryHelpOpen(false)} className="focus:outline-none">
                                        <Icons.HelpCircleIcon className="h-4 w-4 text-gray-400 hover:text-white" />
                                    </button>
                                ))}
                                <input
                                    id="knowledge-category"
                                    type="text"
                                    value={category}
                                    onChange={e => { setCategory(e.target.value); markEdited('category'); }}
                                    list="category-suggestions"
                                    className={inputClass}
                                />
                                <datalist id="category-suggestions">
                                    {existingCategories.map(cat => <option key={cat} value={cat} />)}
                                </datalist>
                            </div>
                            <div>
                                {renderLabel("タグ (Enterで追加)", "tags")}
                                <input
                                    id="knowledge-tags"
                                    type="text"
                                    value={tagInput}
                                    onChange={e => setTagInput(e.target.value)}
                                    onKeyDown={handleTagInputKeyDown}
                                    placeholder="タグを追加..."
                                    className={inputClass}
                                />
                                <div className="flex flex-wrap gap-2 mt-3">
                                    {tags.map(tag => (
                                        <span key={tag} className={`flex items-center gap-1 bg-gray-700 text-white font-medium pl-2.5 pr-1.5 rounded-full ${isMobile ? 'text-sm py-1' : 'text-xs py-1'}`}>
                                            {tag}
                                            <button type="button" onClick={() => handleRemoveTag(tag)} className="text-gray-400 hover:text-white p-1">
                                                <Icons.XIcon className="h-3 w-3" />
                                            </button>
                                        </span>
                                    ))}
                                </div>
                            </div>
                        </div>
                        <div>
                            {renderLabel("内容", "content")}
                            <textarea
                                id="knowledge-content"
                                value={content}
                                onChange={e => { setContent(e.target.value); markEdited('content'); }}
                                rows={10}
                                className={`${inputClass} resize-y`}
                            />
                        </div>
                    </div>
                </form>

                <div 
                    className={`mt-auto border-t border-gray-700 pt-4 bg-gray-900/50 ${isMobile ? 'flex flex-col gap-3 px-4' : 'flex justify-end gap-3 mt-6'}`}
                    style={isMobile ? { paddingBottom: 'calc(1rem + env(safe-area-inset-bottom))' } : {}}
                >
                    <button type="button" onClick={handleCloseRequest} className={buttonClass('bg-gray-600 hover:bg-gray-500')}>
                        <Icons.XIcon className="h-4 w-4" />
                        キャンセル
                    </button>
                    <button type="submit" form="knowledge-form" data-testid="modal-save-button" className={buttonClass('bg-indigo-600 hover:bg-indigo-500 font-bold')}>
                        <Icons.CheckIcon className="h-4 w-4" />
                        保存
                    </button>
                </div>
            </div>
            <HelpPopover
                isOpen={isCategoryHelpOpen}
                targetRef={categoryHelpRef}
                onClose={() => setIsCategoryHelpOpen(false)}
            >
                新しいカテゴリを追加するには、ここに直接名前を入力して保存してください。
            </HelpPopover>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { v4 as uuidv4 } from 'uuid';
import * as Icons from '../icons';
import { getContrastingTextColor } from '../utils';
import { PlotItem, PlotRelation, PlotNodePosition } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
// FIX: The file 'store.ts' does not exist, changed import to 'store/index.ts'.
import { useStore } from '../store/index';
import { PlotBoardTutorial } from './PlotBoardTutorial';

// --- Card Editor Modal ---
const CardEditorModal = ({ card, onSave, onDelete, onClose, plotTypeColors, onUpdateColor, readOnly = false }) => {
    const [title, setTitle] = useState('');
    const [summary, setSummary] = useState('');
    const [selectedDropdownType, setSelectedDropdownType] = useState('');
    const [customType, setCustomType] = useState('');
    const [color, setColor] = useState('#22d3ee');
    const [isDeleting, setIsDeleting] = useState(false);

    const presetTypes = ['章のまとめ', '物語の構成', 'キャラクターアーク', 'サブプロット'];
    const OTHER_OPTION = 'その他（自由記入）';

    const presetTypeColors = {
        '章のまとめ': '#22d3ee', // cyan-400
        '物語の構成': '#2dd4bf', // teal-400
        'キャラクターアーク': '#a855f7', // purple-500
        'サブプロット': '#22c55e', // green-500
    };

    useEffect(() => {
        if (card) {
            setTitle(card.title || '');
            setSummary(card.summary || '');
            const currentType = card.type || presetTypes[0];
            if (presetTypes.includes(currentType)) {
                setSelectedDropdownType(currentType);
                setCustomType('');
                setColor(plotTypeColors[currentType] || presetTypeColors[currentType] || '#6b7280');
            } else {
                setSelectedDropdownType(OTHER_OPTION);
                setCustomType(currentType);
                setColor(plotTypeColors[currentType] || '#6b7280');
            }
        } else { // New card
            setTitle('');
            setSummary('');
            const defaultType = presetTypes[0];
            setSelectedDropdownType(defaultType);
            setCustomType('');
            setColor(plotTypeColors[defaultType] || presetTypeColors[defaultType] || '#22d3ee');
        }
    }, [card, plotTypeColors]);

    const handleSubmit = (e) => {
        e.preventDefault();
        const finalType = selectedDropdownType === OTHER_OPTION ? customType.trim() : selectedDropdownType;
        if (!title.trim() || !finalType) return;
        const newCard = { ...card, id: card?.id || uuidv4(), title, summary, type: finalType, lastModified: Date.now() };
        onSave(newCard);
        if (selectedDropdownType === OTHER_OPTION) {
            onUpdateColor(finalType, color);
        }
    };

    const handleDeleteConfirm = () => {
        onDelete(card.id);
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            e.currentTarget.requestSubmit();
        }
    };

    const handleTypeChange = (e) => {
        const newType = e.target.value;
        setSelectedDropdownType(newType);
        if (newType !== OTHER_OPTION) {
            setColor(plotTypeColors[newType] || presetTypeColors[newType] || '#6b7280');
        }
    };

    const isCustomColorAllowed = selectedDropdownType === OTHER_OPTION;

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex justify-center items-center z-[80]">
            <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-xl p-6 border border-gray-700 max-h-[90vh] flex flex-col">
                <form onSubmit={handleSubmit} onKeyDown={handleKeyDown} className="flex flex-col h-full min-h-0">
                    <h2 className="text-xl font-bold mb-4 text-cyan-400 flex-shrink-0">{readOnly ? 'プロット詳細' : (card?.id ? 'プロットを編集' : 'プロットを新規作成')}</h2>
                    <div className="flex-grow overflow-y-auto pr-2 space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">タイトル <span className="text-red-500">*</span></label>
                            <input type="text" value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white" required disabled={readOnly} />
                        </div>
                        <div className="grid grid-cols-3 gap-4">
                            <div className="col-span-2 space-y-2">
                                <label className="block text-sm font-medium text-gray-300">種別 <span className="text-red-500">*</span></label>
                                <select value={selectedDropdownType} onChange={handleTypeChange} className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white" disabled={readOnly}>
                                    {presetTypes.map(t => <option key={t} value={t}>{t}</option>)}
                                    <option value={OTHER_OPTION}>{OTHER_OPTION}</option>
                                </select>
                                {selectedDropdownType === OTHER_OPTION && (
                                    <input type="text" value={customType} onChange={e => setCustomType(e.target.value)} placeholder="種別名を自由に入力..." className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white" required disabled={readOnly} />
                                )}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-300 mb-1">色</label>
                                <input
                                    type="color"
                                    value={color}
                                    onChange={e => setColor(e.target.value)}
                                    className="w-full h-10 p-1 bg-gray-900 border border-gray-600 rounded-md cursor-pointer disabled:cursor-not-allowed disabled:opacity-50"
                                    disabled={readOnly || !isCustomColorAllowed}
                                    readOnly={readOnly}
                                />
                            </div>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">要約・説明</label>
                            <textarea value={summary} onChange={e => setSummary(e.target.value)} rows={5} className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white resize-y" disabled={readOnly}></textarea>
                        </div>
                    </div>
                    <div className="mt-6 flex justify-between items-center border-t border-gray-700 pt-4 flex-shrink-0">
                        <div>
                            {!readOnly && card?.id && (
                                isDeleting ? (
                                    <div className="flex items-center gap-2">
                                        <span className="text-xs text-red-300 font-bold">本当に削除？</span>
                                        <button type="button" onClick={handleDeleteConfirm} className="px-3 py-1 bg-red-600 text-white rounded text-xs hover:bg-red-500">はい</button>
                                        <button type="button" onClick={() => setIsDeleting(false)} className="px-3 py-1 bg-gray-600 text-white rounded text-xs hover:bg-gray-500">いいえ</button>
                                    </div>
                                ) : (
                                    <button type="button" onClick={() => setIsDeleting(true)} className="flex items-center gap-1 text-red-400 hover:text-red-300 text-sm px-2 py-1 rounded hover:bg-red-900/30 transition">
                                        <Icons.TrashIcon className="h-4 w-4" />
                                        削除
                                    </button>
                                )
                            )}
                        </div>
                        <div className="flex gap-3">
                            <button type="button" onClick={onClose} className="flex items-center gap-2 px-4 py-2 bg-gray-600 rounded-md hover:bg-gray-500 transition text-white btn-pressable">
                                <Icons.XIcon className="h-4 w-4" />
                                {readOnly ? '閉じる' : 'キャンセル'}
                            </button>
                            {!readOnly && <button type="submit" className="flex items-center gap-2 px-4 py-2 bg-cyan-600 rounded-md hover:bg-cyan-500 transition text-white btn-pressable">
                                <Icons.CheckIcon className="h-4 w-4" />
                                保存
                            </button>}
                        </div>
                    </div>
                </form>
            </div>
        </div>
    );
};

// --- Relation Editor Drawer ---
const RelationEditorDrawer = ({ relation, plotItems, onSave, onClose, plotTypeColors }) => {
    const [label, setLabel] = useState('');
    const [customLabel, setCustomLabel] = useState('');
    const [memo, setMemo] = useState('');
    const [color, setColor] = useState('#6b7280');

    const presetRelations = {
        '原因': '#3b82f6', // blue-500
        '結果': '#22c55e', // green-500
        '伏線': '#8b5cf6', // violet-500
        '回収': '#a855f7', // purple-500
        '対立': '#ef4444', // red-500
        'その他': '#6b7280', // gray-500
    };
    const OTHER_OPTION = 'その他';

    useEffect(() => {
        if (relation) {
            const currentLabel = relation.label || '原因';
            if (presetRelations[currentLabel]) {
                setLabel(currentLabel);
                setCustomLabel('');
            } else {
                setLabel(OTHER_OPTION);
                setCustomLabel(currentLabel);
            }
            setMemo(relation.memo || '');
            setColor(relation.color || presetRelations[currentLabel] || '#6b7280');
        }
    }, [relation]);

    useEffect(() => {
        if (label !== OTHER_OPTION) {
            const newColor = presetRelations[label] || '#6b7280';
            setColor(newColor);
        }
    }, [label]);

    const handleSubmit = (e) => {
        e.preventDefault();
        const finalLabel = label === OTHER_OPTION ? customLabel.trim() : label;
        if (!finalLabel) return;
        onSave({ ...relation, label: finalLabel, memo, color });
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            e.currentTarget.requestSubmit();
        }
    };

    const sourceItem = plotItems.find(i => i.id === relation?.source);
    const targetItem = plotItems.find(i => i.id === relation?.target);

    return (
        <div className="absolute bottom-0 left-0 right-0 bg-gray-900/80 backdrop-blur-sm border-t border-gray-700 p-4 z-10">
             <form onSubmit={handleSubmit} onKeyDown={handleKeyDown}>
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-bold text-cyan-400">関係を編集</h2>
                    <button type="button" onClick={onClose} className="p-1 rounded-full hover:bg-gray-700 btn-pressable"><Icons.XIcon className="h-5 w-5 text-white"/></button>
                </div>
                <div className="space-y-4">
                    <p className="text-sm bg-gray-900 p-3 rounded-md text-center">
                        <span className="font-semibold" style={{color: plotTypeColors[sourceItem?.type] || '#fff'}}>{sourceItem?.title}</span>
                        <span className="text-gray-400 mx-2 font-sans">→</span>
                        <span className="font-semibold" style={{color: plotTypeColors[targetItem?.type] || '#fff'}}>{targetItem?.title}</span>
                    </p>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">関係性</label>
                            <select value={label} onChange={e => setLabel(e.target.value)} className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white h-10">
                                {Object.keys(presetRelations).map(p => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">線の色</label>
                            <input 
                                type="color" 
                                value={color} 
                                onChange={e => setColor(e.target.value)} 
                                className="w-full h-10 p-1 bg-gray-900 border border-gray-600 rounded-md cursor-pointer" 
                            />
                        </div>
                    </div>

                    {label === OTHER_OPTION && (
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">関係性を自由入力</label>
                            <input type="text" value={customLabel} onChange={e => setCustomLabel(e.target.value)} placeholder="関係性を入力..." className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white" required />
                        </div>
                    )}

                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-1">メモ (任意)</label>
                        <textarea value={memo} onChange={e => setMemo(e.target.value)} rows={3} className="w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-sm text-white resize-y"></textarea>
                    </div>
                </div>
                <div className="mt-6 flex justify-end gap-3">
                    <button type="button" onClick={onClose} className="flex items-center gap-2 px-4 py-2 bg-gray-600 rounded-md hover:bg-gray-500 transition text-white btn-pressable">
