                    </div>
                    <div className={`flex gap-3 ${isMobile ? 'flex-col w-full order-2' : ''}`}>
                        <button type="button" onClick={handleCloseRequest} className={buttonClass('bg-gray-600 hover:bg-gray-500')}><Icons.XIcon className="h-4 w-4" />キャンセル</button>
