                                                        <span className={`flex-grow ${group.color} font-semibold`}>{group.label}</span>
                                                        <Icons.ChevronRightIcon className="h-4 w-4 text-gray-500" />
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                        {userMode !== 'simple' && currentMenuItems && (
                                            <div className={`absolute right-0 bottom-full mb-2 w-80 bg-gray-700 rounded-lg shadow-lg z-20 border border-gray-600 transition-all duration-300 ease-out transform ${activeMenu ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}>
                                                <div className="p-2 border-b border-gray-700 flex items-center">
                                                    <button type="button" onClick={() => setActiveMenu(null)} className="p-1 text-gray-400 hover:text-white"><Icons.ArrowLeftIcon className="h-5 w-5"/></button>
                                                    <h4 className={`text-white font-bold text-center flex-grow ${activeColor}`}>{activeMenu}</h4>
                                                </div>
                                                <div className="max-h-80 overflow-y-auto">
                                                {currentMenuItems.map(item => (
                                                    <button type="button" key={item.label} onClick={() => handleMenuItemClick(item)} className="w-full text-left p-3 hover:bg-gray-600 transition flex items-start gap-3">
                                                        <item.icon className={`h-5 w-5 ${activeColor} mt-0.5 flex-shrink-0`} />
                                                        <div><p className="font-semibold text-white">{item.label}</p><p className="text-xs text-gray-400">{item.description}</p></div>
                                                    </button>
                                                ))}
                                                </div>
                                            </div>
                                        )}

                                        <div className="flex items-end gap-2">
                                            <div className="flex-grow flex flex-col bg-gray-800 border border-gray-600 rounded-lg overflow-hidden">
                                                <Tooltip helpId="focus_ai" placement="top">
                                                    <textarea 
                                                        ref={userInputRef} 
                                                        id="tutorial-ai-input" 
                                                        rows={userMode === 'simple' ? 4 : 2} 
                                                        value={userInput} 
                                                        onChange={(e) => setUserInput(e.target.value)} 
                                                        onKeyDown={handleKeyDown} 
                                                        onFocus={handleInputFocus}
                                                        placeholder={continuationChoices ? "採用する展開を選択してください" : `AIへの指示を入力...`} 
                                                        className="w-full bg-transparent border-none px-4 py-2 text-sm resize-none overflow-y-auto max-h-96 focus:ring-0 text-white" 
                                                        disabled={isLoading || !!continuationChoices} 
                                                    />
                                                </Tooltip>
                                                <div className="flex items-center gap-2 px-2 pb-1.5">
                                                    {userMode !== 'simple' && (
                                                        <div className="flex justify-between items-center flex-grow">
                                                            <Tooltip helpId="suggestion_history" placement="top">
                                                                <button type="button" onClick={() => setIsHistoryOpen(p => !p)} className="text-[10px] text-gray-500 hover:text-gray-300 flex items-center gap-1 px-1 py-0.5 rounded hover:bg-gray-700">
                                                                    <Icons.HistoryIcon className="h-3 w-3" />
                                                                    <span>履歴</span>
                                                                </button>
                                                            </Tooltip>
                                                            <Tooltip helpId="ai_support_menu" placement="top">
                                                                <button type="button" onClick={() => setIsFeatureMenuOpen(p => !p)} className="p-1 rounded-full text-gray-400 hover:bg-gray-700 hover:text-white" title="AI支援メニュー">
                                                                    <Icons.PlusCircleIcon className="h-4 w-4" />
                                                                </button>
                                                            </Tooltip>
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                            <Tooltip helpId="send_ai" placement="left">
                                                <button 
                                                    onClick={() => submitMessage()} 
                                                    type="button" 
                                                    className="w-12 h-12 flex items-center justify-center text-white rounded-full flex-shrink-0 btn-pressable btn-invert-indigo shadow-lg mb-0.5" 
                                                    disabled={isLoading || !userInput.trim() || !!continuationChoices}
                                                >
                                                    <Icons.SendIcon className="h-6 w-6" />
                                                </button>
                                            </Tooltip>
                                        </div>
                                    </div>
                                </form>
                            </div>
                        </div>

                        {userMode === 'pro' && isHistoryPanelDocked && !isMobile && (
                            <>
                                <HorizontalResizableHandle onMouseDown={handleResizeStart} />
                                <div
                                    style={{ height: `${historyPanelHeight}px` }}
                                    className="flex-shrink-0 overflow-hidden"
                                >
                                    <HistoryPanel />
                                </div>
                            </>
                        )}
                    </div>
                </> )}
            </div>
            {userMode !== 'simple' && (
                <SuggestionHistoryModal 
                    isOpen={isHistoryOpen} 
                    onClose={() => setIsHistoryOpen(false)} 
                    knowledgeSuggestions={archivedKnowledgeSuggestions} 
                    onApproveKnowledge={handleApproveKnowledgeSuggestion} 
                    plotSuggestions={archivedPlotSuggestions} 
                    onApprovePlot={handleApproveSuggestion} 
                    loadingKnowledge={loadingKnowledge} 
                />
            )}
        </div>
    );
};

import { v4 as uuidv4 } from 'uuid';
import { AppState, ChatMessage, NovelChunk, PlotItem, SettingItem } from '../types';
import * as novelApi from '../novelApi';
import * as utilityApi from '../utilityApi';

const initialState = {
    userInput: '',
    isLoading: false,
    aiSuggestions: { knowledge: [], plot: [] } as { knowledge: string[]; plot: PlotItem[] },
    archivedKnowledgeSuggestions: [] as { id: string; content: string }[],
    archivedPlotSuggestions: [] as PlotItem[],
    generationMode: 'write' as 'write' | 'consult',
    isImageGenerating: false,
    continuationChoices: null as { id: string; title: string; text: string }[] | null,
    lastUserPrompt: null as string | null,
};

export interface AiSlice {
    userInput: string;
    isLoading: boolean;
    aiSuggestions: { knowledge: string[]; plot: PlotItem[] };
    archivedKnowledgeSuggestions: { id: string; content: string }[];
    archivedPlotSuggestions: PlotItem[];
    generationMode: 'write' | 'consult';
    isImageGenerating: boolean;
    continuationChoices: { id: string; title: string; text: string }[] | null;
    lastUserPrompt: string | null;

    setUserInput: (input: string) => void;
    setGenerationMode: (mode: 'write' | 'consult') => void;
    setContinuationChoices: (choices: { id: string; title: string; text: string }[] | null) => void;
    submitMessage: (promptOverride?: string) => Promise<void>;
    handleAdoptContinuation: (text: string) => void;
    handleRejectContinuation: (id: string) => void;
    regenerateContinuations: () => Promise<void>;
    handleApproveSuggestion: (suggestion: any, type: 'knowledge' | 'plot') => void;
    handleRejectSuggestion: (suggestion: any, type: 'knowledge' | 'plot') => void;
    setIsImageGenerating: (isGenerating: boolean) => void;
}

export const createAiSlice = (set, get): AiSlice => ({
    ...initialState,
    setUserInput: (input) => set({ userInput: input }),
    setGenerationMode: (mode) => set({ generationMode: mode }),
    setContinuationChoices: (choices) => set({ continuationChoices: choices }),
    submitMessage: async (promptOverride) => {
        const { userInput, isLoading, generationMode, activeProjectId, allProjectsData, userMode, setActiveProjectData } = get();

        // 防御処理: promptOverride が MouseEvent など文字列以外の場合に文字列として扱わないようにする
        const actualOverride = typeof promptOverride === 'string' ? promptOverride : undefined;
        const currentInput = actualOverride || userInput;

        if (!currentInput.trim() || isLoading || !activeProjectId) return;

        const activeProject = allProjectsData[activeProjectId];
        if (!activeProject) return;

        const { chatHistory, aiSettings, knowledgeBase, settings, userProfile } = activeProject;

        const effectiveAiSettings = { ...aiSettings };
        if (userMode === 'simple') {
            effectiveAiSettings.generateMultipleContinuations = false;
        }

        const isRegenerating = !!actualOverride;

        const userMessage: ChatMessage = { role: 'user', text: currentInput, mode: generationMode };
        const chatHistoryForRequest = isRegenerating ? chatHistory : [...chatHistory, userMessage];

        set({ isLoading: true, userInput: '', continuationChoices: null, lastUserPrompt: currentInput });

        if (!isRegenerating) {
            setActiveProjectData(d => ({ ...d, chatHistory: chatHistoryForRequest }), { type: 'ai', label: 'AIへメッセージを送信' });
        }

        const result = await novelApi.generateNovelContinuation({
            prompt: currentInput,
            generationMode,
            aiSettings: effectiveAiSettings,
            knowledgeBase,
            settings,
            characterRelations: activeProject.characterRelations || [],
            novelContent: activeProject.novelContent || [],
            plotBoard: activeProject.plotBoard || [],
            userName: userProfile?.name,
            userMode: userMode,
        });

        set({ isLoading: false });

        if (result.success === false) {
            const errorMessage: ChatMessage = { role: 'assistant', text: `エラーが発生しました: ${result.error.message}`, mode: generationMode };
            setActiveProjectData(d => ({ ...d, chatHistory: [...d.chatHistory, errorMessage] }), { type: 'ai', label: 'AIエラー応答' });
            return;
        }

        const { replyText, newChunk, continuations, suggestions, extractCharacterRequest } = result.data;

        if (extractCharacterRequest) {
            set({ isLoading: true });
            const extractResult = await utilityApi.extractCharacterInfo({
                characterName: extractCharacterRequest.name,
                novelContent: activeProject.novelContent,
            });
            set({ isLoading: false });

            if (extractResult.success === false) {
                alert(`キャラクター「${extractCharacterRequest.name}」の情報の自動抽出に失敗しました。手動で設定してください。\nエラー: ${extractResult.error.message}`);
                get().openModal({ name: extractCharacterRequest.name } as SettingItem, 'character');
                return;
            }

            const initialData = { name: extractCharacterRequest.name, ...extractResult.data };
            get().openModal(initialData as SettingItem, 'character');
            return;
        }

        const suggestionsWithIds = {
            ...suggestions,
            plot: (suggestions.plot || []).map(p => ({...p, id: uuidv4()})),
        };

        let filteredSuggestions = suggestionsWithIds;
        const currentProjectForFilter = get().allProjectsData[activeProjectId];
        if (suggestions.knowledge && suggestions.knowledge.length > 0 && currentProjectForFilter) {
            const existingKnowledgeNames = new Set(currentProjectForFilter.knowledgeBase.map(k => k.name));
            const existingKnowledgeContent = new Set(currentProjectForFilter.knowledgeBase.map(k => k.content));

            const uniqueKnowledgeSuggestions = suggestions.knowledge.filter(s => 
                !existingKnowledgeNames.has(s) && !existingKnowledgeContent.has(s)
            );

            filteredSuggestions = {
                ...suggestionsWithIds,
                knowledge: uniqueKnowledgeSuggestions,
            };
        }

        const assistantMessage: ChatMessage = { role: 'assistant', text: replyText, mode: generationMode };

        setActiveProjectData(d => {
            let finalNovelContent = d.novelContent;
            if (newChunk) {
                finalNovelContent = [...d.novelContent, newChunk];
                set({ highlightedChunkId: newChunk.id });
            }
            return { ...d, chatHistory: [...d.chatHistory, assistantMessage], novelContent: finalNovelContent, lastModified: new Date().toISOString() };
        }, { type: 'ai', label: 'AIからの返答' });

        if (continuations && continuations.length > 0) {
            set({ continuationChoices: continuations.map(c => ({ ...c, id: uuidv4() })) });
        }

        set({ aiSuggestions: filteredSuggestions });
    },
    handleAdoptContinuation: (text) => {
        const newChunk: NovelChunk = { id: uuidv4(), text };
        get().setActiveProjectData(d => ({ ...d, novelContent: [...d.novelContent, newChunk], lastModified: new Date().toISOString() }), { type: 'editor', label: 'AIの提案を採用' });
        set({ continuationChoices: null, highlightedChunkId: newChunk.id });
    },
    handleRejectContinuation: (id) => {
        set(state => ({
            continuationChoices: state.continuationChoices ? state.continuationChoices.filter(c => c.id !== id) : null
        }));
    },
    regenerateContinuations: async () => {
        const { lastUserPrompt, submitMessage } = get();
        if (lastUserPrompt) {
            await submitMessage(lastUserPrompt);
        }
    },
    handleApproveSuggestion: (suggestion, type) => {
        if (type === 'knowledge') {
            get().handleSaveSetting({ name: suggestion as string, content: suggestion as string }, 'knowledge');
            set(state => ({
                archivedKnowledgeSuggestions: state.archivedKnowledgeSuggestions.filter(s => s.content !== suggestion)
            }));
             set(state => ({
                aiSuggestions: {
                    ...state.aiSuggestions,
                    knowledge: state.aiSuggestions.knowledge.filter(s => s !== suggestion)
                }
            }));
        } else if (type === 'plot') {
            const { title, summary, type: plotType, id } = suggestion as PlotItem;
            const newPlotItem = { id, title, summary, type: plotType };
            get().setActiveProjectData(d => ({
                ...d,
                plotBoard: [...d.plotBoard, newPlotItem],
                plotTypeColors: { ...d.plotTypeColors, [plotType]: d.plotTypeColors?.[plotType] || '#6b7280' }
            }), { type: 'plot', label: `プロット「${title}」を追加` });
            set(state => ({
                archivedPlotSuggestions: state.archivedPlotSuggestions.filter(s => s.id !== id)
            }));
            set(state => ({
                aiSuggestions: {
                    ...state.aiSuggestions,
                    plot: state.aiSuggestions.plot.filter(s => s.id !== id)
                }
            }));
        }
    },
    handleRejectSuggestion: (suggestion, type) => {
        set(state => {
            if (type === 'knowledge') {
                const newArchived = { id: uuidv4(), content: suggestion as string };
                return {
                    aiSuggestions: {
                        ...state.aiSuggestions,
                        knowledge: state.aiSuggestions.knowledge.filter(s => s !== suggestion)
                    },
                    archivedKnowledgeSuggestions: [newArchived, ...state.archivedKnowledgeSuggestions]
                };
            } else if (type === 'plot') {
                const plotSuggestion = suggestion as PlotItem;
                 return {
                    aiSuggestions: {
                        ...state.aiSuggestions,
                        plot: state.aiSuggestions.plot.filter(s => s.id !== plotSuggestion.id)
                    },
                     archivedPlotSuggestions: [plotSuggestion, ...state.archivedPlotSuggestions]
                };
            }
            return state;
        });
    },
    setIsImageGenerating: (isGenerating) => set({ isImageGenerating: isGenerating }),
});

import { v4 as uuidv4 } from 'uuid';
import { Project, HistoryNode, HistoryType, HistoryTree } from '../types';

const initialHistoryTree: HistoryTree = {
    nodes: {},
    currentNodeId: null,
    rootId: null,
};

// localStorageの制限を考慮し、保存する履歴の数を大幅に削減
const MAX_HISTORY_NODES = 15;

const setProjectDataWithoutHistory = (set, get, projectData: Project) => {
    const { activeProjectId } = get();
    if (!activeProjectId) return;
    set(state => ({
        allProjectsData: {
            ...state.allProjectsData,
            [activeProjectId]: { ...projectData, historyTree: state.historyTree }
        }
    }));
};

const scopeMatches = (scope: string, type: HistoryType) => {
    if (scope === 'all') return true;
    if (scope === 'text-only') return type === 'editor';
    if (scope === 'ai-only') return type === 'ai';
    if (scope === 'data-only') return ['character', 'world', 'knowledge', 'plot', 'timeline', 'chart', 'settings', 'outline'].includes(type);
    return false;
};

// 指定したノードとその子孫をすべて削除するヘルパー
const deleteRecursive = (nodes: Record<string, HistoryNode>, id: string) => {
    const node = nodes[id];
    if (!node) return;
    node.childrenIds.forEach(childId => deleteRecursive(nodes, childId));
    delete nodes[id];
};

export interface HistorySlice {
    historyTree: HistoryTree;
    addHistory: (projectData: Project, label: { type: HistoryType, label: string }) => void;
    undo: () => void;
    redo: () => void;
    jumpToHistory: (nodeId: string) => void;
}

export const createHistorySlice = (set, get): HistorySlice => ({
    historyTree: initialHistoryTree,
    addHistory: (projectData, label) => {
        set(state => {
            const { historyTree } = state;
            const { nodes, currentNodeId, rootId } = historyTree;

            const newNodeId = uuidv4();
            const newNode: HistoryNode = {
                id: newNodeId,
                parentId: currentNodeId,
                childrenIds: [],
                timestamp: Date.now(),
                type: label.type,
                label: label.label,
                payload: { ...projectData, historyTree: undefined }, 
            };

            const newNodes = { ...nodes, [newNodeId]: newNode };

            if (currentNodeId) {
                const parentNode = newNodes[currentNodeId];
                if (parentNode) {
                    newNodes[currentNodeId] = {
                        ...parentNode,
                        childrenIds: [...parentNode.childrenIds, newNodeId],
                    };
                }
            } else if (!rootId) {
                // ルートがない場合はこれがルートになる
                return {
                    historyTree: {
                        nodes: newNodes,
                        currentNodeId: newNodeId,
                        rootId: newNodeId,
                    }
                };
            }

            // 履歴が上限を超えた場合、古いブランチを削除してストレージを節約
            const nodeCount = Object.keys(newNodes).length;
            if (nodeCount > MAX_HISTORY_NODES && rootId) {
                const root = newNodes[rootId];
                if (root && root.childrenIds.length > 1) {
                    // 枝分かれしている場合、一番古い（現在のパスではない）枝を優先的に削除
                    // ここでは簡易的に、最も古い子ノードとその子孫を削除
                    const oldestChildId = root.childrenIds[0];
                    deleteRecursive(newNodes, oldestChildId);
                    newNodes[rootId] = {
                        ...root,
                        childrenIds: root.childrenIds.slice(1),
                    };
                } else if (root && root.childrenIds.length === 1) {
                    // 単一のパスの場合、ルートを一つ進める
                    const oldRootId = rootId;
                    const newRootId = root.childrenIds[0];
                    const newRoot = newNodes[newRootId];
                    if (newRoot) {
                        newRoot.parentId = null;
                        delete newNodes[oldRootId];
                        return {
                            historyTree: {
                                ...historyTree,
                                nodes: newNodes,
                                currentNodeId: newNodeId,
                                rootId: newRootId,
                            }
                        };
                    }
                }
            }

            return {
                historyTree: {
                    ...historyTree,
                    nodes: newNodes,
                    currentNodeId: newNodeId,
                }
            };
        });
    },
    undo: () => {
        const { historyTree, activeProjectId, undoScope, allProjectsData, showToast, addHistory } = get();
        if (!activeProjectId || !historyTree.currentNodeId) return;

        const { nodes, currentNodeId } = historyTree;
        const currentNode = nodes[currentNodeId];

        if (undoScope === 'all') {
            const parentId = currentNode.parentId;
            if (parentId) {
                const parentNode = nodes[parentId];
                setProjectDataWithoutHistory(set, get, parentNode.payload);
                set(state => ({
                    historyTree: { ...state.historyTree, currentNodeId: parentId }
                }));
                showToast(`「${currentNode.label}」を元に戻しました`);
            } else {
                showToast("これ以上元に戻せません");
            }
            return;
        }

        // 選択的なUndo
        let actionNodeId = currentNodeId;
        while (actionNodeId && !scopeMatches(undoScope, nodes[actionNodeId].type)) {
            actionNodeId = nodes[actionNodeId].parentId;
        }

        if (!actionNodeId) {
            showToast("元に戻せる操作が見つかりませんでした");
            return;
        }

        const actionNode = nodes[actionNodeId];
        const sourceNodeId = actionNode.parentId;
        if (!sourceNodeId) return;

        const sourceProject = nodes[sourceNodeId].payload;
        const currentProject = allProjectsData[activeProjectId];

        let newProject = { ...currentProject };
        let label = "";
        let historyType: HistoryType = 'settings';

        if (undoScope === 'text-only') {
            newProject.novelContent = sourceProject.novelContent;
            label = "本文のみ元に戻す";
            historyType = 'editor';
        } else if (undoScope === 'ai-only') {
            newProject.chatHistory = sourceProject.chatHistory;
            label = "AIチャットのみ元に戻す";
            historyType = 'ai';
        } else if (undoScope === 'data-only') {
            newProject.settings = sourceProject.settings;
            newProject.knowledgeBase = sourceProject.knowledgeBase;
            newProject.plotBoard = sourceProject.plotBoard;
            newProject.timeline = sourceProject.timeline;
            label = "データのみ元に戻す";
        }

        newProject.lastModified = new Date().toISOString();
        setProjectDataWithoutHistory(set, get, newProject);
        addHistory(newProject, { type: historyType, label: label });
        showToast(label);
    },
    redo: () => {
        get().showToast("タイムトラベルパネルから履歴を選択してください", "info");
    },
    jumpToHistory: (nodeId) => {
        const { historyTree, activeProjectId, showToast } = get();
        if (!activeProjectId || !historyTree.nodes[nodeId]) return;

        const targetNode = historyTree.nodes[nodeId];
        setProjectDataWithoutHistory(set, get, targetNode.payload);
        set(state => ({
            historyTree: { ...state.historyTree, currentNodeId: nodeId }
        }));
        showToast(`履歴「${targetNode.label}」に戻りました`);
    },
});

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { AppState, AppActions } from '../types';
import { createProjectSlice, ProjectSlice } from './projectSlice';
import { createUiSlice, UiSlice } from './uiSlice';
import { createDataSlice, DataSlice } from './dataSlice';
import { createAiSlice, AiSlice } from './aiSlice';
import { createHistorySlice, HistorySlice } from './historySlice';
import { createTutorialSlice, TutorialSlice } from './tutorialSlice';
import { createFormSlice, FormSlice } from './formSlice';

// 容量制限エラーに対応するためのカスタムストレージラッパー
const customStorage = {
    getItem: (name: string) => localStorage.getItem(name),
    setItem: (name: string, value: string) => {
        try {
            localStorage.setItem(name, value);
        } catch (e) {
            if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
                console.error('LocalStorage quota exceeded. Reducing history and retrying...');
                // ここで緊急のデータ削減ロジックを走らせることも可能
                // ユーザーに警告を表示
                alert('ブラウザの保存容量がいっぱいです。古いプロジェクトを削除するか、エクスポートして整理してください。');
            } else {
                throw e;
            }
        }
    },
    removeItem: (name: string) => localStorage.removeItem(name),
};

export const useStore = create<AppState & AppActions & ProjectSlice & UiSlice & DataSlice & AiSlice & HistorySlice & TutorialSlice & FormSlice>()(
    persist(
        (set, get, api) => ({
            ...createProjectSlice(set, get),
            ...createUiSlice(set, get),
            ...createDataSlice(set, get),
            ...createAiSlice(set, get),
            ...createHistorySlice(set, get),
            ...createTutorialSlice(set, get),
            ...createFormSlice(set, get),
            loadInitialState: () => {},
        }),
        {
            name: 'NOVEL_WRITER_storage',
            storage: createJSONStorage(() => customStorage),
            partialize: (state) => {
                // 各プロジェクト内の冗長な履歴データを削除してから保存
                const projects = { ...state.allProjectsData };
                Object.keys(projects).forEach(id => {
                    if (projects[id]) {
                        // プロジェクトオブジェクト内の historyTree はグローバル側にあるため間引く
                        const { historyTree, ...rest } = projects[id] as any;
                        projects[id] = rest;
                    }
                });

                return {
                    allProjectsData: projects,
                    activeProjectId: state.activeProjectId,
                    isLeftSidebarOpen: state.isLeftSidebarOpen,
                    isRightSidebarOpen: state.isRightSidebarOpen,
                    leftSidebarWidth: state.leftSidebarWidth,
                    rightSidebarWidth: state.rightSidebarWidth,
                    isNewChunkInputOpen: state.isNewChunkInputOpen,
                    hasCompletedGlobalTutorial: state.hasCompletedGlobalTutorial,
                    userMode: state.userMode,
                    undoScope: state.undoScope,
                    historyTree: state.historyTree,
                    pinnedSettingIds: state.pinnedSettingIds,
                };
            },
        }
    )
);

import { SettingItem, KnowledgeItem, Project, NovelChunk, AiSettings } from './types';
import { defaultAiSettings, defaultDisplaySettings } from './constants';

export const getContrastingTextColor = (hex) => {
    if (!hex) return '#FFFFFF';
    let hexValue = hex.startsWith('#') ? hex.substring(1) : hex;

    if (hexValue.length === 3) {
        hexValue = hexValue.split('').map(char => char + char).join('');
    }

    if (hexValue.length !== 6) {
        return '#FFFFFF';
    }

    const r = parseInt(hexValue.substring(0, 2), 16);
    const g = parseInt(hexValue.substring(2, 4), 16);
    const b = parseInt(hexValue.substring(4, 6), 16);

    const luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255;

    return luminance > 0.5 ? '#000000' : '#FFFFFF';
};

export interface ParseMarkdownOptions {
    applySpeakerColor?: boolean;
    applyKnowledgeLinks?: boolean;
    applyCustomColors?: boolean;
}

const createAnchorId = (text: string) => {
    try {
        // Use encodeURIComponent which is safe for creating valid id attributes and href values.
        return encodeURIComponent(text.trim().toLowerCase().replace(/\s+/g, '-').replace(/[?]/g, ''));
    } catch (e) {
        return 'invalid-id';
    }
};


export const parseMarkdown = (
    text: string, 
    characters: SettingItem[] = [], 
    knowledgeBase: KnowledgeItem[] = [], 
    aiSettings?: AiSettings,
    options?: ParseMarkdownOptions
) => {
    if (!text) return '';

    const defaultOptions: ParseMarkdownOptions = {
        applySpeakerColor: true,
        applyKnowledgeLinks: true,
        applyCustomColors: true,
    };
    const { applySpeakerColor, applyKnowledgeLinks, applyCustomColors } = { ...defaultOptions, ...options };

    // 1. Escape HTML special characters first to prevent rendering of arbitrary HTML.
    let processedText = text
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#039;');

    // Pre-process to avoid parsing inside code blocks
    const codeBlocks: string[] = [];
    processedText = processedText.replace(/```([\s\S]*?)```/gs, (match, code) => {
        const placeholder = `__CODEBLOCK_${codeBlocks.length}__`;
        const escapedCode = code.trim().replace(/</g, '&lt;').replace(/>/g, '&gt;');
        codeBlocks.push(`<pre><code class="language-plaintext">${escapedCode}</code></pre>`);
        return placeholder;
    });
     processedText = processedText.replace(/`([^`]+?)`/g, '<code>$1</code>');

    // 2. Process our special tags.

    // Handle <speaker> tags for dialogue color. This is the primary, most reliable method.
    if (applySpeakerColor && aiSettings?.applySpeakerColorToDialogue) {
        const characterColorMap = new Map(characters.filter(c => c.themeColor).map(c => [c.name, c.themeColor]));

        processedText = processedText.replace(/&lt;speaker\s+name\s*=\s*(["'])([\s\S]*?)\1\s*&gt;([\s\S]*?)&lt;\/speaker&gt;/gi, (match, quote, name, content) => {
            const color = characterColorMap.get(name.trim());
            if (!color) return content; // No color found, just strip the tag.

            // The user wants to color only the dialogue part, regardless of whether the speaker name is shown.
            // This applies the color only to text within `「...」` or `『...』`.
            return content.replace(/(「[\s\S]*?」|『[\s\S]*?』)/g, (dialogueMatch) => {
                return `<span style="color:${color}">${dialogueMatch}</span>`;
            });
        });
    }
    // Safety net: Strip any remaining speaker tags that were not processed.
    processedText = processedText.replace(/&lt;speaker.*?&gt;([\s\S]*?)&lt;\/speaker&gt;/gi, '$1');

    // Fallback for older content that doesn't use <speaker> tags.
    // This logic specifically targets the "Name ON / Color ON" case.
    if (applySpeakerColor && aiSettings?.applySpeakerColorToDialogue && aiSettings.showSpeakerInDialogue) {
        const characterColorMap = new Map(characters.filter(c => c.themeColor).map(c => [c.name, c.themeColor]));
        processedText = processedText.split('\n').map(line => {
            // Don't re-process lines that were already colored by the speaker tag logic above.
            if (line.includes('<span style="color:')) return line;

            // Match `Name「...」` at the start of the line.
            const match = line.match(/^([^「」『』\s&<]+)\s*(「[\s\S]*?」|『[\s\S]*?』)/);
            if (match) {
                const name = match[1].trim();
                const color = characterColorMap.get(name);
                if (color) {
                    const dialogue = match[2];
                    return line.replace(dialogue, `<span style="color:${color}">${dialogue}</span>`);
                }
            }
            return line;
        }).join('\n');
    }

    // Handle custom <c:color> tags
    if (applyCustomColors) {
        processedText = processedText.replace(/&lt;c:([a-zA-Z0-9#]+?)&gt;(.*?)&lt;\/c&gt;/gs, (match, color, content) => {
            const sanitizedColor = color.match(/^[a-zA-Z0-9#]+$/) ? color : 'inherit';
            return `<span style="color:${sanitizedColor}">${content}</span>`;
        });
    }

    // 3. Process standard markdown.
    processedText = processedText.replace(/{([^|]+?)\|(.+?)}/g, '<ruby>$1<rt>$2</rt></ruby>');
    processedText = processedText.replace(/\*\*(.*?)\*\*/gs, '<strong>$1</strong>');
    processedText = processedText.replace(/__(.*?)__/gs, '<u>$1</u>');
    processedText = processedText.replace(/\*(.*?)\*/gs, '<em>$1</em>');
    processedText = processedText.replace(/~~(.*?)~~/gs, '<s>$1</s>');

    // Links (internal for docs, anchors for page jumps, and external)
    processedText = processedText.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (match, text, url) => {
        if (url.startsWith('./')) {
            // Use a data attribute to prevent navigation and handle via JS
            const docKey = url.substring(2);
            return `<a href="#" data-doc-key="${docKey}" class="internal-link">${text}</a>`;
        }
        if (url.startsWith('#')) {
            // Create a valid href for the anchor link
            const anchorId = createAnchorId(url.substring(1));
            return `<a href="#${anchorId}" class="anchor-link">${text}</a>`;
        }
        if (url.startsWith('http')) {
            return `<a href="${url}" target="_blank" rel="noopener noreferrer">${text}</a>`;
        }
        return `<a href="${url}">${text}</a>`;
    });

    processedText = processedText.replace(/^### (.*$)/gm, (_, title) => `<h3 id="${createAnchorId(title)}">${title}</h3>`);
    processedText = processedText.replace(/^## (.*$)/gm, (_, title) => `<h2 id="${createAnchorId(title)}">${title}</h2>`);
    processedText = processedText.replace(/^# (?!#)(.*$)/gm, (_, title) => `<h1 class="chapter-title" id="${createAnchorId(title)}">${title}</h1>`);

    processedText = processedText.replace(/&lt;br\s*\/?&gt;/gi, '<br />');

    // Table: just remove pipes for better readability as plain text
    processedText = processedText.replace(/^ *\|(.+)\| *$/gm, (line) => {
        if (line.match(/^ *\|[-:| ]+\| *$/)) return ''; // Remove separator line
        return line.replace(/\|/g, '  ').trim();
    });

    // Lists
    processedText = processedText.replace(/^\s*[-*+] (.*$)/gm, '<li>$1</li>');
    processedText = processedText.replace(/^\s*\d+\. (.*$)/gm, '<li>$1</li>'); // Treat ordered as unordered for simplicity
    processedText = processedText.replace(/(<\/li>\n<li>)/g, '</li><li>'); // Join list items
    processedText = processedText.replace(/(<li>.*<\/li>)/gs, '<ul>$1</ul>');
    processedText = processedText.replace(/<\/ul>\s*<ul>/g, '');


    // 4. Process knowledge links
    if (applyKnowledgeLinks) {
        const linkableNames = new Set([
            ...(knowledgeBase || []).map(k => k.name),
            ...(characters || []).map(c => c.name)
        ]);
        const knowledgeNameMap = new Map((knowledgeBase || []).map(k => [k.name, k]));
        const seenLinks = new Set<string>();

        processedText = processedText.replace(/\[\[(.*?)\]\]/g, (match, linkName) => {
            const trimmedName = linkName.trim();

            if (!linkableNames.has(trimmedName)) {
                // If the item doesn't exist in either characters or knowledge, just strip the brackets.
                return trimmedName;
            }

            // It exists. If it's a knowledge item, create a link.
            const knowledgeItem = knowledgeNameMap.get(trimmedName);
            if (knowledgeItem) {
                if (seenLinks.has(trimmedName)) {
                    return trimmedName; // Don't link subsequent appearances
                }
                seenLinks.add(trimmedName);
                const title = (knowledgeItem.category && knowledgeItem.category !== '未分類') 
                    ? `${knowledgeItem.category}: ${knowledgeItem.name}` 
                    : knowledgeItem.name;
                return `<a href="#" class="knowledge-link" data-knowledge-id="${knowledgeItem.id}" title="${title}">${trimmedName}</a>`;
            }

            // It must be a character name. Just strip the brackets as there's no linking feature.
            return trimmedName;
        });
    }

    // 5. Clean up any remaining special syntax if their features were disabled
    if (!applySpeakerColor) {
        processedText = processedText.replace(/&lt;speaker.*?&gt;([\s\S]*?)&lt;\/speaker&gt;/gi, '$1');
    }
    if (!applyCustomColors) {
        processedText = processedText.replace(/&lt;c:([a-zA-Z0-9#]+?)&gt;(.*?)&lt;\/c&gt;/gs, '$2');
    }
    if (!applyKnowledgeLinks) {
        processedText = processedText.replace(/\[\[(.*?)\]\]/g, '$1');
    }

    // Restore code blocks
    codeBlocks.forEach((block, index) => {
        processedText = processedText.replace(`__CODEBLOCK_${index}__`, block);
    });

    // Add paragraph tags
    // FIX: Preserve empty lines by returning <br /> instead of an empty string
    processedText = processedText.split('\n').map(p => {
        if (p.trim() === '') return '<br />'; 
        if (p.trim().startsWith('<h') || p.trim().startsWith('<ul') || p.trim().startsWith('<ol') || p.trim().startsWith('<pre')) {
            return p;
        }
        return `<p>${p}</p>`;
    }).join('');


    return processedText;
};


export const getChapterChunks = (novelContent: NovelChunk[], chapterId: string): NovelChunk[] => {
    const isUncategorizedChapter = novelContent.find(c => c.id === chapterId && !c.text.startsWith('# '));

    if (isUncategorizedChapter) {
        const firstTitleIndex = novelContent.findIndex(c => c.text.startsWith('# '));
        if (firstTitleIndex === -1) {
            return [...novelContent];
        }
        return novelContent.slice(0, firstTitleIndex);
    }

    const chapterStartIndex = novelContent.findIndex(c => c.id === chapterId);
    if (chapterStartIndex === -1) return [];

    let chapterEndIndex = novelContent.findIndex((c, i) => i > chapterStartIndex && c.text.startsWith('# '));
    if (chapterEndIndex === -1) {
        chapterEndIndex = novelContent.length;
    }

    return novelContent.slice(chapterStartIndex, chapterEndIndex);
};


// --- Project Data Validation ---
const isObject = (value: any): value is Record<string, any> => value !== null && typeof value === 'object' && !Array.isArray(value);
const isString = (value: any): value is string => typeof value === 'string';
const isArray = (value: any): value is any[] => Array.isArray(value);

const validateArrayItems = <T>(arr: any, validator: (item: any) => item is T): T[] => {
    if (!isArray(arr)) return [];
    return arr.filter(validator);
};

const isValidNovelChunk = (item: any): item is NovelChunk => isObject(item) && isString(item.id) && isString(item.text);
const isValidSettingItem = (item: any): item is SettingItem => isObject(item) && isString(item.id) && isString(item.name) && isString(item.type);
const isValidKnowledgeItem = (item: any): item is KnowledgeItem => {
    if (!isObject(item) || !isString(item.id) || !isString(item.name)) return false;

    // Sanitize tags: ensure it's an array of strings.
    if ('tags' in item && !isArray(item.tags)) {
        // If tags exist but aren't an array (e.g., a string from an old version), try to convert.
        if (isString(item.tags)) {
            item.tags = item.tags.split(',').map(t => t.trim()).filter(Boolean);
        } else {
            // If it's something else, just reset it.
            item.tags = [];
        }
    } else if ('tags' in item && isArray(item.tags)) {
        // Ensure all items in the array are strings
        item.tags = item.tags.filter(isString);
    } else if (!('tags' in item)) {
        item.tags = [];
    }

    return true;
};
